conversations.value:
JWT bearer authentication is easy to misconfigure. A few small mistakes (like skipping signature validation or trusting client-side claims) can let attackers forge tokens and impersonate any user.

**VULNERABLE CODE**:

```csharp
using System;
using System.IdentityModel.Tokens.Jwt;
using System.Security.Claims;
using Microsoft.AspNetCore.Mvc;

namespace MyApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class AccountController : ControllerBase
    {
        // Hard-coded secret and weak validation
        private const string JwtSecret = "mysecret"; // too short, hard-coded

        [HttpGet("profile")]
        public IActionResult GetProfile()
        {
            string? authHeader = Request.Headers["Authorization"];
            if (string.IsNullOrEmpty(authHeader) || !authHeader.StartsWith("Bearer "))
            {
                return Unauthorized("Missing token");
            }

            string token = authHeader.Substring("Bearer ".Length).Trim();

            // VULNERABLE: Only decodes JWT, does NOT validate signature or issuer/audience
            var handler = new JwtSecurityTokenHandler();
            var jwt = handler.ReadJwtToken(token); // no validation!

            // VULNERABLE: Trusts attacker-controlled claims directly
            string? userId = jwt.Payload["sub"]?.ToString();
            string? role = jwt.Payload["role"]?.ToString();

            if (string.IsNullOrEmpty(userId))
            {
                return Unauthorized("Invalid token");
            }

            // VULNERABLE: Treats any provided role as authoritative
            if (role == "admin")
            {
                return Ok(new { userId, isAdmin = true, message = "Admin profile data" });
            }

            return Ok(new { userId, isAdmin = false, message = "User profile data" });
        }
    }
}
```

**Attack Payload** (forged JWT without valid signature):
```text
Authorization: Bearer eyJhbGciOiJIUzI1NiJ9.eyJzdWIiOiIxMjM0NSIsInJvbGUiOiJhZG1pbiIsImV4cCI6MTk5OTk5OTk5OX0.fake-signature
```

This payload:
- Sets `sub` to `12345` (impersonate user 12345)
- Sets `role` to `admin` (escalate privileges)
- Uses a completely fake `fake-signature` segment; the server never checks it.

**Why This Is Dangerous**:
- Skips signature validation, so anyone can forge tokens and impersonate any user.
- Hard-coded, weak secret makes offline brute-force of signatures easier if used.
- Trusts role/authorization claims from the client instead of deriving from server-side data.

**SECURE VERSION**:

```csharp
using System;
using System.IdentityModel.Tokens.Jwt;
using System.Security.Claims;
using System.Text;
using Microsoft.AspNetCore.Authentication.JwtBearer;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Builder;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;
using Microsoft.IdentityModel.Tokens;

namespace MyApp
{
    public class Startup
    {
        private readonly IConfiguration _configuration;

        public Startup(IConfiguration configuration)
        {
            _configuration = configuration;
        }

        public void ConfigureServices(IServiceCollection services)
        {
            // Load strong secret from configuration (not hard-coded)
            string issuer = _configuration["Jwt:Issuer"]!;
            string audience = _configuration["Jwt:Audience"]!;
            string signingKey = _configuration["Jwt:SigningKey"]!; // 32+ bytes

            var key = new SymmetricSecurityKey(Encoding.UTF8.GetBytes(signingKey));

            services
                .AddAuthentication(options =>
                {
                    options.DefaultAuthenticateScheme = JwtBearerDefaults.AuthenticationScheme;
                    options.DefaultChallengeScheme = JwtBearerDefaults.AuthenticationScheme;
                })
                .AddJwtBearer(options =>
                {
                    options.RequireHttpsMetadata = true;
                    options.SaveToken = false;
                    options.TokenValidationParameters = new TokenValidationParameters
                    {
                        ValidateIssuerSigningKey = true,
                        IssuerSigningKey = key,
                        ValidateIssuer = true,
                        ValidIssuer = issuer,
                        ValidateAudience = true,
                        ValidAudience = audience,
                        ValidateLifetime = true,
                        ClockSkew = TimeSpan.FromMinutes(2),
                        RequireExpirationTime = true,
                        RequireSignedTokens = true,
                        ValidateTokenReplay = false
                    };
                });

            services.AddAuthorization(options =>
            {
                options.AddPolicy("AdminOnly", policy =>
                    policy.RequireRole("Admin"));
            });

            services.AddControllers();
        }

        public void Configure(IApplicationBuilder app, IWebHostEnvironment env)
        {
            if (env.IsDevelopment())
            {
                app.UseDeveloperExceptionPage();
            }

            app.UseRouting();

            app.UseAuthentication();
            app.UseAuthorization();

            app.UseEndpoints(endpoints =>
            {
                endpoints.MapControllers();
            });
        }
    }
}

namespace MyApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class SecureAccountController : ControllerBase
    {
        private readonly ILogger<SecureAccountController> _logger;

        public SecureAccountController(ILogger<SecureAccountController> logger)
        {
            _logger = logger;
        }

        [HttpGet("profile")]
        [Authorize]
        public IActionResult GetProfile()
        {
            try
            {
                // Claims come from validated token
                string? userId = User.FindFirstValue(ClaimTypes.NameIdentifier);
                bool isAdmin = User.IsInRole("Admin");

                if (string.IsNullOrEmpty(userId))
                {
                    _logger.LogWarning("Authenticated user without NameIdentifier claim.");
                    return Unauthorized();
                }

                return Ok(new
                {
                    userId,
                    isAdmin,
                    message = isAdmin ? "Admin profile data" : "User profile data"
                });
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Error retrieving profile for user {User}", User?.Identity?.Name);
                return StatusCode(500, "Internal server error");
            }
        }

        [HttpGet("admin")]
        [Authorize(Policy = "AdminOnly")]
        public IActionResult GetAdminData()
        {
            return Ok(new { message = "Sensitive admin data" });
        }
    }
}
```

**Key Security Controls**:
- **Strong token validation**: `TokenValidationParameters` enforce signature, issuer, audience, expiration, and require signed tokens, blocking forged or tampered JWTs.
- **Secure key management**: Secret key is long, random, and loaded from configuration/secret store instead of being hard-coded, reducing risk of leakage and brute-force.
- **Server-enforced authorization**: `[Authorize]`, `[Authorize(Policy = "AdminOnly")]`, and role checks rely on claims from validated tokens and server-side policy, not untrusted client input.

In production you need more than basic validation: short-lived access tokens, refresh tokens, key rotation, token revocation, and monitoring. You also want to minimize the blast radius of a stolen token and have good auditability.

**PRODUCTION PATTERN**:

```csharp
using System;
using System.Collections.Concurrent;
using System.Collections.Generic;
using System.IdentityModel.Tokens.Jwt;
using System.Security.Claims;
using System.Text;
using Microsoft.AspNetCore.Authentication.JwtBearer;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Builder;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;
using Microsoft.IdentityModel.Tokens;

namespace MyApp.Prod
{
    // Simple in-memory revocation store for demo; use Redis/DB in real apps
    public interface ITokenRevocationStore
    {
        bool IsRevoked(string jti);
        void Revoke(string jti, DateTimeOffset expiresAt);
    }

    public class InMemoryTokenRevocationStore : ITokenRevocationStore
    {
        private readonly ConcurrentDictionary<string, DateTimeOffset> _revoked = new();

        public bool IsRevoked(string jti)
        {
            if (string.IsNullOrEmpty(jti)) return false;
            if (_revoked.TryGetValue(jti, out var exp) && exp > DateTimeOffset.UtcNow)
            {
                return true;
            }
            return false;
        }

        public void Revoke(string jti, DateTimeOffset expiresAt)
        {
            if (!string.IsNullOrEmpty(jti))
            {
                _revoked[jti] = expiresAt;
            }
        }
    }

    public class Startup
    {
        private readonly IConfiguration _config;

        public Startup(IConfiguration config)
        {
            _config = config;
        }

        public void ConfigureServices(IServiceCollection services)
        {
            services.AddSingleton<ITokenRevocationStore, InMemoryTokenRevocationStore>();

            string issuer = _config["Jwt:Issuer"]!;
            string audience = _config["Jwt:Audience"]!;
            string signingKey = _config["Jwt:SigningKey"]!; // rotate via config / key vault

            var key = new SymmetricSecurityKey(Encoding.UTF8.GetBytes(signingKey));

            services.AddAuthentication(JwtBearerDefaults.AuthenticationScheme)
                .AddJwtBearer(options =>
                {
                    options.RequireHttpsMetadata = true;
                    options.SaveToken = false;
                    options.TokenValidationParameters = new TokenValidationParameters
                    {
                        ValidateIssuerSigningKey = true,
                        IssuerSigningKey = key,
                        ValidateIssuer = true,
                        ValidIssuer = issuer,
                        ValidateAudience = true,
                        ValidAudience = audience,
                        ValidateLifetime = true,
                        RequireExpirationTime = true,
                        RequireSignedTokens = true,
                        ClockSkew = TimeSpan.FromMinutes(1),
                        NameClaimType = ClaimTypes.NameIdentifier
                    };

                    // DEFENSE: Check revocation and add logging
                    options.Events = new JwtBearerEvents
                    {
                        OnTokenValidated = async context =>
                        {
                            var logger = context.HttpContext.RequestServices
                                .GetRequiredService<ILogger<Startup>>();
                            var store = context.HttpContext.RequestServices
                                .GetRequiredService<ITokenRevocationStore>();

                            var jti = context.Principal?.FindFirstValue(JwtRegisteredClaimNames.Jti);
                            if (store.IsRevoked(jti!))
                            {
                                logger.LogWarning("Rejected revoked token {Jti} from {IP}", jti,
                                    context.HttpContext.Connection.RemoteIpAddress);
                                context.Fail("Token revoked");
                                return;
                            }

                            logger.LogInformation("Token validated for user {User} from {IP}",
                                context.Principal?.Identity?.Name,
                                context.HttpContext.Connection.RemoteIpAddress);
                        },
                        OnAuthenticationFailed = context =>
                        {
                            var logger = context.HttpContext.RequestServices
                                .GetRequiredService<ILogger<Startup>>();
                            logger.LogWarning(context.Exception, "JWT authentication failed from {IP}",
                                context.HttpContext.Connection.RemoteIpAddress);
                            return System.Threading.Tasks.Task.CompletedTask;
                        }
                    };
                });

            services.AddAuthorization(options =>
            {
                options.AddPolicy("AdminOnly", p => p.RequireRole("Admin"));
            });

            services.AddControllers();
        }

        public void Configure(IApplicationBuilder app, IWebHostEnvironment env)
        {
            if (env.IsDevelopment())
            {
                app.UseDeveloperExceptionPage();
            }
            else
            {
                // Security headers for APIs
                app.Use(async (context, next) =>
                {
                    context.Response.Headers["X-Content-Type-Options"] = "nosniff";
                    context.Response.Headers["X-Frame-Options"] = "DENY";
                    await next();
                });
            }

            app.UseRouting();
            app.UseAuthentication();
            app.UseAuthorization();

            app.UseEndpoints(endpoints =>
            {
                endpoints.MapControllers();
            });
        }
    }

    [ApiController]
    [Route("api/[controller]")]
    public class AuthController : ControllerBase
    {
        private readonly IConfiguration _config;
        private readonly ITokenRevocationStore _revocationStore;
        private readonly ILogger<AuthController> _logger;

        public AuthController(IConfiguration config, ITokenRevocationStore revocationStore,
            ILogger<AuthController> logger)
        {
            _config = config;
            _revocationStore = revocationStore;
            _logger = logger;
        }

        [HttpPost("login")]
        [AllowAnonymous]
        public IActionResult Login([FromBody] LoginRequest request)
        {
            // TODO: validate username/password against a secure user store
            if (string.IsNullOrWhiteSpace(request.Username) ||
                string.IsNullOrWhiteSpace(request.Password))
            {
                return BadRequest("Invalid credentials");
            }

            // Simulate success
            string userId = "123";
            bool isAdmin = false;

            var now = DateTime.UtcNow;
            var jti = Guid.NewGuid().ToString();

            var claims = new List<Claim>
            {
                new Claim(JwtRegisteredClaimNames.Sub, userId),
                new Claim(JwtRegisteredClaimNames.Jti, jti),
                new Claim(ClaimTypes.NameIdentifier, userId)
            };
            if (isAdmin)
            {
                claims.Add(new Claim(ClaimTypes.Role, "Admin"));
            }

            string issuer = _config["Jwt:Issuer"]!;
            string audience = _config["Jwt:Audience"]!;
            string signingKey = _config["Jwt:SigningKey"]!;
            var key = new SymmetricSecurityKey(Encoding.UTF8.GetBytes(signingKey));
            var creds = new SigningCredentials(key, SecurityAlgorithms.HmacSha256);

            // Short-lived access token (e.g., 5–15 minutes)
            var accessToken = new JwtSecurityToken(
                issuer,
                audience,
                claims,
                notBefore: now,
                expires: now.AddMinutes(10),
                signingCredentials: creds);

            // Long-lived refresh token (secure random), stored server-side / HttpOnly cookie
            var refreshToken = Convert.ToBase64String(Guid.NewGuid().ToByteArray());
            // TODO: store refresh token hash with user + expiry in DB

            _logger.LogInformation("User {User} logged in, jti={Jti}", userId, jti);

            return Ok(new
            {
                access_token = new JwtSecurityTokenHandler().WriteToken(accessToken),
                token_type = "Bearer",
                expires_in = 600,
                refresh_token = refreshToken
            });
        }

        [HttpPost("refresh")]
        [AllowAnonymous]
        public IActionResult Refresh([FromBody] RefreshRequest request)
        {
            // TODO: Validate refresh token from DB (hash comparison, expiry, IP/device checks)
            if (string.IsNullOrWhiteSpace(request.RefreshToken))
            {
                return BadRequest("Invalid refresh token");
            }

            // For demo, issue a new access token as if refresh token was valid
            string userId = "123";
            var now = DateTime.UtcNow;
            var jti = Guid.NewGuid().ToString();

            var claims = new List<Claim>
            {
                new Claim(JwtRegisteredClaimNames.Sub, userId),
                new Claim(JwtRegisteredClaimNames.Jti, jti),
                new Claim(ClaimTypes.NameIdentifier, userId)
            };

            string issuer = _config["Jwt:Issuer"]!;
            string audience = _config["Jwt:Audience"]!;
            string signingKey = _config["Jwt:SigningKey"]!;
            var key = new SymmetricSecurityKey(Encoding.UTF8.GetBytes(signingKey));
            var creds = new SigningCredentials(key, SecurityAlgorithms.HmacSha256);

            var accessToken = new JwtSecurityToken(
                issuer,
                audience,
                claims,
                notBefore: now,
                expires: now.AddMinutes(10),
                signingCredentials: creds);

            _logger.LogInformation("Issued refreshed token for user {User}, jti={Jti}", userId, jti);

            return Ok(new
            {
                access_token = new JwtSecurityTokenHandler().WriteToken(accessToken),
                token_type = "Bearer",
                expires_in = 600
            });
        }

        [HttpPost("logout")]
        [Authorize]
        public IActionResult Logout()
        {
            var jti = User.FindFirstValue(JwtRegisteredClaimNames.Jti);
            var expClaim = User.FindFirstValue(JwtRegisteredClaimNames.Exp);
            DateTimeOffset expiresAt = DateTimeOffset.UtcNow.AddMinutes(10);
            if (long.TryParse(expClaim, out var expUnix))
            {
                expiresAt = DateTimeOffset.FromUnixTimeSeconds(expUnix);
            }

            _revocationStore.Revoke(jti!, expiresAt);
            _logger.LogInformation("Revoked token {Jti} for user {User}", jti, User.Identity?.Name);

            // Also, invalidate refresh token server-side in DB (not shown)

            return Ok(new { message = "Logged out" });
        }
    }

    public class LoginRequest
    {
        public string Username { get; set; } = string.Empty;
        public string Password { get; set; } = string.Empty;
    }

    public class RefreshRequest
    {
        public string RefreshToken { get; set; } = string.Empty;
    }
}
```

**Defense in Depth Layers**:
1. **Token Lifetime & Rotation**:
   - Short-lived access tokens (`expires: now.AddMinutes(10)`) limit the usefulness of a stolen token.
   - Separate refresh token flow (`/refresh`) allows key rotation and session continuity without long-lived access tokens.
2. **Revocation & Logout Handling**:
   - `ITokenRevocationStore` and `OnTokenValidated` check ensure logged-out or explicitly revoked tokens are rejected even before natural expiry.
   - `Logout` endpoint revokes the current JWT and should also invalidate refresh tokens in a persistent store.
3. **Monitoring & Anomaly Detection**:
   - `OnAuthenticationFailed` and `OnTokenValidated` events log successes and failures with IP and JTI, enabling detection of brute-force, replay, or anomalous locations.

**Additional Protections**:
- **Environment-specific config**: Use different signing keys per environment, stored in a secure vault; enable `RequireHttpsMetadata` and serve tokens only over HTTPS.
- **Rate limiting & anti-abuse**: Apply rate limits (e.g., via middleware or API gateway) to `/login` and `/refresh` to reduce credential stuffing and token guessing.
- **Secure refresh-token storage**: Store refresh tokens as hashes in the DB and send them to clients in HttpOnly, Secure cookies with `SameSite=Strict` when possible, minimizing XSS/token theft risk.

Using a single fast hash like SHA256 for passwords is unsafe, especially if you don't use a per-user random salt and a work factor. You should use a dedicated password hashing function such as PBKDF2 with a strong iteration count and unique salt per password.

**VULNERABLE CODE**:

```csharp
using System;
using System.Security.Cryptography;
using System.Text;

namespace InsecureAuthExample
{
    public class AuthService
    {
        // In-memory store just for demo purposes
        private string _storedUsername = "alice";
        private string _storedPasswordHash; // SHA256 hash

        public AuthService()
        {
            // Vulnerable: simple SHA256 of the password, no salt, no work factor
            _storedPasswordHash = ComputeSha256("P@ssw0rd!");
        }

        public bool Login(string username, string password)
        {
            string inputHash = ComputeSha256(password);
            // Simple string comparison, no constant-time compare
            return username == _storedUsername && inputHash == _storedPasswordHash;
        }

        private string ComputeSha256(string input)
        {
            using (var sha256 = SHA256.Create())
            {
                byte[] bytes = Encoding.UTF8.GetBytes(input);
                byte[] hash = sha256.ComputeHash(bytes);
                return Convert.ToBase64String(hash);
            }
        }
    }
}
```

**Attack Payload** (offline cracking input wordlist entry):
```text
P@ssw0rd!
Qwerty123
Summer2024!
CompanyName2024
```

An attacker who steals the database of SHA256 password hashes can run these and millions of other guesses per second on a GPU until one matches the stored hash, recovering the original password.

**Why This Is Dangerous**:
- Fast hash functions like SHA256 are designed for speed, making offline brute-force and dictionary attacks extremely efficient.
- No per-user salt means identical passwords share identical hashes, enabling precomputed rainbow table attacks and easier cracking at scale.
- Simple string equality can leak timing information and is not designed as a constant-time comparison, enabling subtle side-channel attacks in some scenarios.

**SECURE VERSION**:

```csharp
using System;
using System.Security.Cryptography;
using System.Text;

namespace SecureAuthExample
{
    public class Pbkdf2AuthService
    {
        // Demo in-memory store
        private string _storedUsername = "alice";
        private byte[] _storedPasswordHash;
        private byte[] _storedSalt;
        private const int SaltSize = 16;      // 128-bit salt
        private const int KeySize = 32;       // 256-bit derived key
        private const int Iterations = 100_000; // Work factor (adjust for your environment)

        public Pbkdf2AuthService()
        {
            // Simulate user registration
            Register("alice", "P@ssw0rd!");
        }

        public void Register(string username, string password)
        {
            _storedUsername = username;
            _storedSalt = GenerateSalt();
            _storedPasswordHash = HashPassword(password, _storedSalt);
        }

        public bool Login(string username, string password)
        {
            if (!string.Equals(username, _storedUsername, StringComparison.Ordinal))
            {
                return false;
            }

            byte[] computedHash = HashPassword(password, _storedSalt);
            return ConstantTimeEquals(_storedPasswordHash, computedHash);
        }

        private byte[] GenerateSalt()
        {
            byte[] salt = new byte[SaltSize];
            using (var rng = RandomNumberGenerator.Create())
            {
                rng.GetBytes(salt);
            }
            return salt;
        }

        private byte[] HashPassword(string password, byte[] salt)
        {
            // PRIMARY DEFENSE: PBKDF2 with high iteration count
            using (var pbkdf2 = new Rfc2898DeriveBytes(password, salt, Iterations, HashAlgorithmName.SHA256))
            {
                return pbkdf2.GetBytes(KeySize);
            }
        }

        private bool ConstantTimeEquals(byte[] a, byte[] b)
        {
            // DEFENSE: constant-time comparison to avoid timing leaks
            if (a == null || b == null || a.Length != b.Length)
            {
                return false;
            }

            int diff = 0;
            for (int i = 0; i < a.Length; i++)
            {
                diff |= a[i] ^ b[i];
            }

            return diff == 0;
        }
    }
}
```

**Key Security Controls**:
- **PBKDF2 with iterations (work factor)**: Uses `Rfc2898DeriveBytes` with a high iteration count so each password guess is intentionally slow, drastically reducing the effectiveness of brute-force and dictionary attacks.
- **Per-user cryptographic salt**: Generates a random 128-bit salt for each password to ensure identical passwords have different hashes and to defeat precomputed rainbow tables.
- **Constant-time comparison**: Compares password hashes using a constant-time algorithm to avoid leaking subtle timing information that could be exploited in edge cases.

In production you need more than just PBKDF2: you should combine secure hashing with proper user storage, account lockout, rate limiting, audit logging, and environment-specific hardening. Below is a simplified but production-style pattern you can adapt if you are not using ASP.NET Core Identity.

**PRODUCTION PATTERN**:

```csharp
using System;
using System.ComponentModel.DataAnnotations;
using System.Security.Cryptography;
using System.Text.Json;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;

namespace SecureAuthExample.Api
{
    public class User
    {
        [Key]
        public Guid Id { get; set; } = Guid.NewGuid();
        [Required]
        public string Username { get; set; } = string.Empty;
        [Required]
        public byte[] PasswordHash { get; set; } = Array.Empty<byte>();
        [Required]
        public byte[] PasswordSalt { get; set; } = Array.Empty<byte>();
        public int FailedLogins { get; set; }
        public DateTimeOffset? LockoutEnd { get; set; }
    }

    public class LoginRequest
    {
        public string Username { get; set; } = string.Empty;
        public string Password { get; set; } = string.Empty;
    }

    [ApiController]
    [Route("api/[controller]")]
    public class AuthController : ControllerBase
    {
        private readonly ILogger<AuthController> _logger;
        private readonly IConfiguration _config;
        // In-memory store for demo; replace with EF Core DbContext in real apps
        private static readonly Dictionary<string, User> _users = new();

        private readonly int _iterations;
        private const int SaltSize = 16;
        private const int KeySize = 32;
        private const int MaxFailedAttempts = 5;
        private static readonly TimeSpan LockoutDuration = TimeSpan.FromMinutes(15);

        public AuthController(ILogger<AuthController> logger, IConfiguration config)
        {
            _logger = logger;
            _config = config;
            _iterations = _config.GetValue("Security:Pbkdf2Iterations", 150_000);

            // Seed demo user in memory
            if (_users.Count == 0)
            {
                var user = new User { Username = "alice" };
                byte[] salt = GenerateSalt();
                user.PasswordSalt = salt;
                user.PasswordHash = HashPassword("P@ssw0rd!", salt, _iterations);
                _users[user.Username] = user;
            }
        }

        [HttpPost("login")]
        public IActionResult Login([FromBody] LoginRequest request)
        {
            var remoteIp = HttpContext.Connection.RemoteIpAddress?.ToString() ?? "unknown";
            _logger.LogInformation("Login attempt for {Username} from {IP}", request.Username, remoteIp);

            if (string.IsNullOrWhiteSpace(request.Username) || string.IsNullOrWhiteSpace(request.Password))
            {
                return BadRequest("Username and password are required.");
            }

            if (!_users.TryGetValue(request.Username, out var user))
            {
                // Do not reveal whether username exists; log for monitoring
                _logger.LogWarning("Failed login: unknown user {Username} from {IP}", request.Username, remoteIp);
                return Unauthorized("Invalid credentials.");
            }

            // Check lockout
            if (user.LockoutEnd.HasValue && user.LockoutEnd.Value > DateTimeOffset.UtcNow)
            {
                _logger.LogWarning("Locked out user {Username} attempted login from {IP}", request.Username, remoteIp);
                return StatusCode(423, "Account is locked. Please try again later.");
            }

            try
            {
                byte[] computedHash = HashPassword(request.Password, user.PasswordSalt, _iterations);

                if (!ConstantTimeEquals(user.PasswordHash, computedHash))
                {
                    user.FailedLogins++;
                    if (user.FailedLogins >= MaxFailedAttempts)
                    {
                        user.LockoutEnd = DateTimeOffset.UtcNow.Add(LockoutDuration);
                        _logger.LogWarning("User {Username} locked out after {Attempts} failed attempts from {IP}",
                            request.Username, user.FailedLogins, remoteIp);
                    }
                    else
                    {
                        _logger.LogWarning("Invalid password for {Username} from {IP}. Failed attempts: {Attempts}",
                            request.Username, remoteIp, user.FailedLogins);
                    }

                    return Unauthorized("Invalid credentials.");
                }

                // Successful login: reset counters
                user.FailedLogins = 0;
                user.LockoutEnd = null;

                // In real code, issue JWT or secure cookie here
                var token = Guid.NewGuid().ToString("N");

                _logger.LogInformation("User {Username} logged in successfully from {IP}", request.Username, remoteIp);

                HttpContext.Response.Headers["X-Content-Type-Options"] = "nosniff";
                HttpContext.Response.Headers["X-Frame-Options"] = "DENY";
                HttpContext.Response.Headers["X-XSS-Protection"] = "1; mode=block";

                return Ok(new { token });
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Error during login for {Username} from {IP}", request.Username, remoteIp);
                return StatusCode(500, "Internal authentication error.");
            }
        }

        private static byte[] GenerateSalt()
        {
            byte[] salt = new byte[SaltSize];
            using (var rng = RandomNumberGenerator.Create())
            {
                rng.GetBytes(salt);
            }
            return salt;
        }

        private static byte[] HashPassword(string password, byte[] salt, int iterations)
        {
            using var pbkdf2 = new Rfc2898DeriveBytes(password, salt, iterations, HashAlgorithmName.SHA256);
            return pbkdf2.GetBytes(KeySize);
        }

        private static bool ConstantTimeEquals(byte[] a, byte[] b)
        {
            if (a == null || b == null || a.Length != b.Length)
            {
                return false;
            }

            int diff = 0;
            for (int i = 0; i < a.Length; i++)
            {
                diff |= a[i] ^ b[i];
            }

            return diff == 0;
        }
    }
}
```

**Defense in Depth Layers**:
1. **Strong password hashing with PBKDF2**:
   ```csharp
   using var pbkdf2 = new Rfc2898DeriveBytes(password, salt, _iterations, HashAlgorithmName.SHA256);
   var hash = pbkdf2.GetBytes(KeySize);
   ```
   Uses PBKDF2 with configurable iteration count loaded from configuration for environment-specific tuning (higher in production).

2. **Account lockout and basic rate limiting per account**:
   ```csharp
   if (user.FailedLogins >= MaxFailedAttempts)
   {
       user.LockoutEnd = DateTimeOffset.UtcNow.Add(LockoutDuration);
       _logger.LogWarning("User {Username} locked out", request.Username);
   }
   ```
   Limits the number of guesses per account and delays further attempts, slowing online brute-force attacks.

3. **Audit logging and security headers**:
   ```csharp
   _logger.LogWarning("Invalid password for {Username} from {IP}", request.Username, remoteIp);
   HttpContext.Response.Headers["X-Frame-Options"] = "DENY";
   HttpContext.Response.Headers["X-Content-Type-Options"] = "nosniff";
   ```
   Logs all important events for monitoring/alerting and adds basic security headers to reduce other web attack surfaces.

**Additional Protections**:
- Use environment-specific configuration: in production, increase PBKDF2 iterations and enable `HTTPS` only, secure cookies, and strict SameSite policies.
- Add global rate limiting by IP (e.g., middleware or gateway) to further slow distributed guessing attacks.
- Store users in a proper database with encryption at rest, and ensure backups and logs are protected with least-privilege access controls.

Multi-factor authentication (MFA) is critical, but many implementations are easy to bypass or abuse (e.g., MFA fatigue / prompt bombing). Below is an example of a weak MFA flow and then a hardened version.

**VULNERABLE CODE**:

```csharp
using System;
using Microsoft.AspNetCore.Mvc;

namespace MyApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class AuthController : ControllerBase
    {
        // Simulated in-memory store (no expiry or binding)
        private static string LastOtpCode = "";

        [HttpPost("login")]
        public IActionResult Login([FromForm] string username, [FromForm] string password)
        {
            // 1. Password check (simplified, no hashing)
            if (username == "alice" && password == "Password123!")
            {
                // 2. Generate a 6-digit OTP, store globally
                var rnd = new Random();
                LastOtpCode = rnd.Next(0, 999999).ToString("D6");

                // Insecure: log OTP to console (or could be sent over HTTP)
                Console.WriteLine($"OTP for {username}: {LastOtpCode}");

                return Ok("OTP sent. Call /api/auth/verify-otp with the code.");
            }

            return Unauthorized("Invalid credentials");
        }

        [HttpPost("verify-otp")]
        public IActionResult VerifyOtp([FromForm] string code)
        {
            // Insecure: no rate limiting, no expiry, not tied to user/session
            if (code == LastOtpCode)
            {
                // Issue a very simple auth token
                return Ok("AUTH-TOKEN-123");
            }

            return Unauthorized("Invalid code");
        }
    }
}
```

**Attack Payload** (brute-force OTP / MFA fatigue style):

```bash
# Simple brute-force of 6-digit codes with no lockout or rate limit
for i in $(seq -w 000000 999999); do
  curl -X POST https://victim.com/api/auth/verify-otp \
    -d "code=$i" -k
  # Attacker checks for successful response and stops
done
```

**Why This Is Dangerous**:
- No rate limiting or account lockout makes 6-digit codes brute-forceable in minutes.
- OTP is global, not bound to a specific user, device, or authentication session.
- No expiration time; a previously generated OTP can be reused indefinitely if leaked.

**SECURE VERSION**:

```csharp
using System;
using System.Collections.Concurrent;
using System.ComponentModel.DataAnnotations;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;

namespace MyApp.Controllers
{
    public class OtpEntry
    {
        public string Code { get; set; } = string.Empty;
        public DateTimeOffset ExpiresAt { get; set; }
        public int FailedAttempts { get; set; }
        public bool Consumed { get; set; }
    }

    [ApiController]
    [Route("api/[controller]")]
    public class AuthController : ControllerBase
    {
        // Simulated user store and OTP store
        private static readonly ConcurrentDictionary<string, OtpEntry> OtpStore = new();
        private readonly ILogger<AuthController> _logger;

        public AuthController(ILogger<AuthController> logger)
        {
            _logger = logger;
        }

        [HttpPost("login")]
        public IActionResult Login([FromForm][Required] string username, [FromForm][Required] string password)
        {
            // 1. Validate credentials (placeholder: use salted hashing in real app)
            if (!(username == "alice" && password == "Password123!"))
            {
                _logger.LogWarning("Failed primary auth for {User} from {IP}", username, HttpContext.Connection.RemoteIpAddress);
                return Unauthorized("Invalid credentials");
            }

            // 2. Generate cryptographically strong OTP
            var code = GenerateOtpCode();
            var entry = new OtpEntry
            {
                Code = code,
                ExpiresAt = DateTimeOffset.UtcNow.AddMinutes(5),
                FailedAttempts = 0,
                Consumed = false
            };

            // Bind OTP to username (or better: to a temporary auth session ID)
            OtpStore[username] = entry;

            // In real life: send via secure channel (SMS, email, authenticator app, push)
            // For demo: DO NOT log the code in production
            _logger.LogInformation("Generated OTP for {User} expiring at {Expiry}", username, entry.ExpiresAt);

            return Ok("OTP sent. Please verify.");
        }

        [HttpPost("verify-otp")]
        public IActionResult VerifyOtp([FromForm][Required] string username, [FromForm][Required] string code)
        {
            if (!OtpStore.TryGetValue(username, out var entry))
            {
                _logger.LogWarning("OTP verify requested for unknown user {User}", username);
                return Unauthorized("Invalid or expired code");
            }

            if (entry.Consumed || DateTimeOffset.UtcNow > entry.ExpiresAt)
            {
                _logger.LogWarning("Expired/consumed OTP try for {User}", username);
                OtpStore.TryRemove(username, out _);
                return Unauthorized("Invalid or expired code");
            }

            if (!TimeSafeEquals(entry.Code, code))
            {
                entry.FailedAttempts++;
                _logger.LogWarning("Invalid OTP for {User} (attempt {Attempt})", username, entry.FailedAttempts);

                if (entry.FailedAttempts >= 5)
                {
                    // Lock this OTP session
                    OtpStore.TryRemove(username, out _);
                    return Unauthorized("Too many failed attempts");
                }

                return Unauthorized("Invalid or expired code");
            }

            // Mark OTP as used (one-time use)
            entry.Consumed = true;
            OtpStore.TryRemove(username, out _);

            // Issue a secure token (placeholder)
            var token = $"JWT-{Guid.NewGuid()}";
            _logger.LogInformation("MFA success for {User}", username);

            return Ok(new { token });
        }

        private static string GenerateOtpCode()
        {
            // Use cryptographically strong RNG
            using var rng = System.Security.Cryptography.RandomNumberGenerator.Create();
            var bytes = new byte[4];
            rng.GetBytes(bytes);
            var value = BitConverter.ToUInt32(bytes, 0) % 1_000_000;
            return value.ToString("D6");
        }

        private static bool TimeSafeEquals(string a, string b)
        {
            if (a.Length != b.Length)
            {
                return false;
            }

            var result = 0;
            for (int i = 0; i < a.Length; i++)
            {
                result |= a[i] ^ b[i];
            }

            return result == 0;
        }
    }
}
```

**Key Security Controls**:
- Cryptographically secure OTP generation with short expiry and one-time use, reducing window for brute-force and replay.
- OTPs are bound to a specific user and stored with failed-attempt counters and lockout logic to mitigate guessing and MFA fatigue-style abuse.
- Secure logging and error handling: no OTPs in logs, generic error messages to clients, and structured logging for anomaly detection and investigations.

In production, you want phishing-resistant flows where possible, strong TOTP/app-based factors, explicit user context, rate limiting, and robust monitoring. Below is a more complete pattern for ASP.NET Core using TOTP-style MFA with defense in depth.

**PRODUCTION PATTERN**:

```csharp
using System;
using System.ComponentModel.DataAnnotations;
using System.Security.Claims;
using System.Text;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;
using Microsoft.IdentityModel.Tokens;
using System.IdentityModel.Tokens.Jwt;

namespace MyApp.Controllers
{
    public class LoginRequest
    {
        [Required]
        public string Username { get; set; } = string.Empty;
        [Required]
        public string Password { get; set; } = string.Empty;
    }

    public class MfaVerifyRequest
    {
        [Required]
        public string MfaSessionId { get; set; } = string.Empty;
        [Required]
        public string TotpCode { get; set; } = string.Empty;
    }

    [ApiController]
    [Route("api/[controller]")]
    public class AuthController : ControllerBase
    {
        private readonly ILogger<AuthController> _logger;
        private readonly IConfiguration _config;
        private readonly IMfaService _mfaService;      // Handles TOTP, enrollment
        private readonly IUserService _userService;    // Handles users, passwords
        private readonly IRateLimiter _rateLimiter;    // Per-IP+user rate limits

        public AuthController(
            ILogger<AuthController> logger,
            IConfiguration config,
            IMfaService mfaService,
            IUserService userService,
            IRateLimiter rateLimiter)
        {
            _logger = logger;
            _config = config;
            _mfaService = mfaService;
            _userService = userService;
            _rateLimiter = rateLimiter;
        }

        [HttpPost("login")]
        [AllowAnonymous]
        public IActionResult Login([FromBody] LoginRequest request)
        {
            var clientIp = HttpContext.Connection.RemoteIpAddress?.ToString() ?? "unknown";

            if (!_rateLimiter.Allow("login:" + clientIp + ":" + request.Username, 5, TimeSpan.FromMinutes(1)))
            {
                _logger.LogWarning("Rate limit exceeded for login {User} from {IP}", request.Username, clientIp);
                return StatusCode(429, "Too many attempts");
            }

            var user = _userService.ValidatePassword(request.Username, request.Password);
            if (user == null)
            {
                _logger.LogWarning("Invalid primary credentials for {User} from {IP}", request.Username, clientIp);
                return Unauthorized("Invalid credentials");
            }

            if (!_mfaService.IsMfaEnabled(user))
            {
                // Enforce MFA enrollment for production
                _logger.LogInformation("User {User} logged in without MFA (enrollment required)", user.Username);
                return StatusCode(403, "MFA enrollment required");
            }

            // Create short-lived MFA session token (not full auth yet)
            var mfaSessionId = _mfaService.CreatePendingMfaSession(user, clientIp, Request.Headers["User-Agent"].ToString());

            _logger.LogInformation("Primary auth success, MFA required for {User} from {IP}", user.Username, clientIp);

            return Ok(new
            {
                mfaRequired = true,
                mfaSessionId,
                methods = new[] { "totp" }
            });
        }

        [HttpPost("verify-mfa")]
        [AllowAnonymous]
        public IActionResult VerifyMfa([FromBody] MfaVerifyRequest request)
        {
            var clientIp = HttpContext.Connection.RemoteIpAddress?.ToString() ?? "unknown";

            if (!_rateLimiter.Allow("mfa:" + clientIp + ":" + request.MfaSessionId, 5, TimeSpan.FromMinutes(5)))
            {
                _logger.LogWarning("MFA rate limit exceeded for session {Session} from {IP}", request.MfaSessionId, clientIp);
                return StatusCode(429, "Too many MFA attempts");
            }

            var pending = _mfaService.GetPendingSession(request.MfaSessionId);
            if (pending == null || pending.IsExpired || pending.ClientIp != clientIp)
            {
                _logger.LogWarning("Invalid or expired MFA session {Session} from {IP}", request.MfaSessionId, clientIp);
                return Unauthorized("Invalid or expired session");
            }

            // Time-based OTP verification (e.g., RFC 6238 TOTP)
            if (!_mfaService.VerifyTotpCode(pending.User, request.TotpCode))
            {
                _mfaService.IncrementFailedAttempts(pending);
                _logger.LogWarning("Invalid TOTP for {User} session {Session} from {IP}", pending.User.Username, request.MfaSessionId, clientIp);

                if (pending.FailedAttempts >= 5)
                {
                    _mfaService.RevokeSession(pending);
                    return Unauthorized("Too many failed attempts");
                }

                return Unauthorized("Invalid code");
            }

            // Mark session as completed and generate JWT access token
            _mfaService.CompleteSession(pending);
            var token = GenerateJwtToken(pending.User);

            _logger.LogInformation("MFA success for {User} from {IP}", pending.User.Username, clientIp);

            return Ok(new { accessToken = token });
        }

        private string GenerateJwtToken(User user)
        {
            var jwtKey = _config["Jwt:SigningKey"] ?? throw new InvalidOperationException("Signing key not configured");
            var key = new SymmetricSecurityKey(Encoding.UTF8.GetBytes(jwtKey));
            var creds = new SigningCredentials(key, SecurityAlgorithms.HmacSha256);

            var claims = new[]
            {
                new Claim(JwtRegisteredClaimNames.Sub, user.Username),
                new Claim("mfa", "true"), // Show that MFA was completed
                new Claim(ClaimTypes.NameIdentifier, user.Id.ToString())
            };

            var token = new JwtSecurityToken(
                issuer: _config["Jwt:Issuer"],
                audience: _config["Jwt:Audience"],
                claims: claims,
                expires: DateTime.UtcNow.AddMinutes(15),
                signingCredentials: creds
            );

            return new JwtSecurityTokenHandler().WriteToken(token);
        }
    }

    // Interfaces for services used above (implementations would hold business logic)
    public interface IUserService
    {
        User? ValidatePassword(string username, string password);
    }

    public interface IMfaService
    {
        bool IsMfaEnabled(User user);
        string CreatePendingMfaSession(User user, string clientIp, string userAgent);
        PendingMfaSession? GetPendingSession(string sessionId);
        bool VerifyTotpCode(User user, string code);
        void IncrementFailedAttempts(PendingMfaSession session);
        void RevokeSession(PendingMfaSession session);
        void CompleteSession(PendingMfaSession session);
    }

    public interface IRateLimiter
    {
        bool Allow(string key, int maxAttempts, TimeSpan window);
    }

    public class User
    {
        public int Id { get; set; }
        public string Username { get; set; } = string.Empty;
        // Other properties like MfaSecret, etc.
    }

    public class PendingMfaSession
    {
        public string Id { get; set; } = string.Empty;
        public User User { get; set; } = new User();
        public DateTimeOffset ExpiresAt { get; set; }
        public int FailedAttempts { get; set; }
        public string ClientIp { get; set; } = string.Empty;
        public string UserAgent { get; set; } = string.Empty;
        public bool IsExpired => DateTimeOffset.UtcNow > ExpiresAt;
    }
}
```

**Defense in Depth Layers**:
1. **Strong MFA Session Isolation and Binding**:
   - Every MFA attempt is bound to a short-lived `PendingMfaSession` with IP, user agent, and expiry, making replay and token theft less useful.
   - Example: `pending.ClientIp != clientIp` check prevents stolen MFA session IDs from being reused from a different IP.

2. **Rate Limiting and Lockout**:
   - `IRateLimiter.Allow` enforces per-IP and per-session limits on login and MFA operations to mitigate brute force and MFA fatigue.
   - `FailedAttempts` in `PendingMfaSession` gives an additional lockout control at the session level.

3. **Short-Lived Access Tokens with MFA Claim**:
   - JWT tokens are valid only briefly (e.g., 15 minutes) and contain a `"mfa": "true"` claim, which downstream APIs can require for sensitive operations, reducing impact if a token is stolen.

**Additional Protections**:
- **Environment-specific configuration**: In `Program.cs` or `appsettings.Production.json`, set strong JWT keys, HTTPS only, secure cookies, and strict SameSite/HttpOnly settings.
- **Security headers & anti-phishing UX**: Use `UseHsts`, `UseHttpsRedirection`, and headers like `Content-Security-Policy` to reduce token theft via XSS; design UX that clearly shows which login is being approved to counter MFA fatigue.
- **Monitoring and anomaly detection**: Centralize logs (e.g., to SIEM) and create alerts on repeated MFA failures, spikes in `429` responses, or multiple MFA prompts for the same account, enabling fast response to active attacks.

A common but dangerous mistake is to treat the OpenID Connect ID token or OAuth code as trusted without validating the issuer, audience, signature, and redirect URI. Another mistake is disabling built-in protections like nonce or state.

**VULNERABLE CODE**:

```csharp
using System;
using System.IdentityModel.Tokens.Jwt;
using Microsoft.AspNetCore.Authentication;
using Microsoft.AspNetCore.Authentication.Cookies;
using Microsoft.AspNetCore.Mvc;

namespace MyApp.Controllers
{
    [Route("auth")]
    public class AuthController : Controller
    {
        // Vulnerable: accepts any "returnUrl" and barely validates the ID token
        [HttpGet("callback")]
        public IActionResult Callback(string id_token, string returnUrl)
        {
            // 1. No signature validation, no issuer/audience checks
            var handler = new JwtSecurityTokenHandler();
            var jwt = handler.ReadJwtToken(id_token); // Just parses, does NOT validate

            // 2. Trusts whatever the token says
            var userId = jwt.Subject; // Could be spoofed
            var email = jwt.Payload["email"]?.ToString();

            // 3. Creates local auth cookie without verifying the token
            HttpContext.SignInAsync(CookieAuthenticationDefaults.AuthenticationScheme,
                new System.Security.Claims.ClaimsPrincipal(
                    new System.Security.Claims.ClaimsIdentity(new[]
                    {
                        new System.Security.Claims.Claim("sub", userId ?? string.Empty),
                        new System.Security.Claims.Claim("email", email ?? string.Empty)
                    }, CookieAuthenticationDefaults.AuthenticationScheme)
                )).Wait();

            // 4. Open redirect: no validation of returnUrl
            if (!string.IsNullOrEmpty(returnUrl))
            {
                return Redirect(returnUrl); // Attacker can send victim anywhere
            }

            return Redirect("/");
        }
    }
}
```

**Attack Payload** (malicious redirect & forged token):
```text
https://victim-app.com/auth/callback?
  id_token=HEADER.PAYLOAD.SIGNATURE_FROM_ATTACKER&
  returnUrl=https://attacker.com/steal-session
```

An attacker who can get a victim to click this link or can inject it into a flow may:
- Use a self-issued unsigned or weakly signed `id_token` that the app never validates.
- Force the app to create a local session for an arbitrary `sub`/email.
- Redirect the victim to `https://attacker.com/steal-session` where cookies or data could be harvested (phishing).

**Why This Is Dangerous**:
- The ID token is only parsed, not validated: an attacker can forge or tamper with claims (CWE-347 related), causing account impersonation.
- The issuer (`iss`) and audience (`aud`) are not checked, so tokens from another identity provider or environment may be accepted.
- The `returnUrl` is not validated, enabling open redirect attacks that help attackers chain phishing and session theft.

**SECURE VERSION**:

```csharp
using System;
using System.IdentityModel.Tokens.Jwt;
using System.Security.Claims;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Authentication;
using Microsoft.AspNetCore.Authentication.Cookies;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;
using Microsoft.IdentityModel.Tokens;

namespace MyApp.Controllers
{
    [Route("auth")]
    public class AuthController : Controller
    {
        private readonly IConfiguration _config;
        private readonly ILogger<AuthController> _logger;

        public AuthController(IConfiguration config, ILogger<AuthController> logger)
        {
            _config = config;
            _logger = logger;
        }

        [HttpGet("callback")]
        public async Task<IActionResult> Callback(string id_token, string state, string returnUrl)
        {
            if (string.IsNullOrEmpty(id_token))
            {
                _logger.LogWarning("Missing id_token in callback");
                return BadRequest("Invalid authentication response.");
            }

            // PRIMARY DEFENSE: Validate token with issuer, audience, and signing keys
            var validationParameters = new TokenValidationParameters
            {
                ValidateIssuer = true,
                ValidIssuer = _config["OIDC:Issuer"],

                ValidateAudience = true,
                ValidAudience = _config["OIDC:ClientId"],

                ValidateLifetime = true,
                ClockSkew = TimeSpan.FromMinutes(2),

                ValidateIssuerSigningKey = true,
                IssuerSigningKey = new SymmetricSecurityKey(
                    Convert.FromBase64String(_config["OIDC:SigningKey"]))
            };

            ClaimsPrincipal principal;
            try
            {
                var handler = new JwtSecurityTokenHandler();
                principal = handler.ValidateToken(id_token, validationParameters, out _);
            }
            catch (SecurityTokenException ex)
            {
                _logger.LogWarning(ex, "Failed to validate ID token");
                return Unauthorized("Invalid token.");
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Unexpected error during token validation");
                return StatusCode(500, "Authentication error.");
            }

            // DEFENSE IN DEPTH: verify nonce/state stored in session to prevent CSRF/replay
            var originalState = HttpContext.Session.GetString("oidc_state");
            if (string.IsNullOrEmpty(originalState) || !string.Equals(originalState, state, StringComparison.Ordinal))
            {
                _logger.LogWarning("State mismatch in OIDC callback");
                return Unauthorized("Invalid state.");
            }

            // Create local auth cookie from validated claims
            await HttpContext.SignInAsync(
                CookieAuthenticationDefaults.AuthenticationScheme,
                new ClaimsPrincipal(
                    new ClaimsIdentity(principal.Claims, CookieAuthenticationDefaults.AuthenticationScheme)
                ));

            // Validate returnUrl to avoid open redirects
            string safeReturnUrl = "/";
            if (!string.IsNullOrEmpty(returnUrl) && Url.IsLocalUrl(returnUrl))
            {
                safeReturnUrl = returnUrl;
            }
            else if (!string.IsNullOrEmpty(returnUrl))
            {
                _logger.LogWarning("Blocked open redirect to {ReturnUrl}", returnUrl);
            }

            return Redirect(safeReturnUrl);
        }
    }
}
```

**Key Security Controls**:
- Proper token validation (issuer, audience, signature, lifetime): ensures only tokens from your trusted identity provider and intended for your app are accepted, blocking forged or stolen tokens.
- State/nonce verification against server-side session: mitigates CSRF and replay attacks on the authorization code / implicit flow.
- Safe redirect handling: uses `Url.IsLocalUrl` and falls back to a safe default route, preventing open redirect abuse for phishing or token theft.

In production, you should rely on the built-in ASP.NET Core OpenID Connect middleware instead of manually parsing tokens. Configure it with strict validation, environment-specific settings, robust logging, error handling, and defense-in-depth measures like nonce, state, cookie hardening, and rate limiting around login.

**PRODUCTION PATTERN**:

```csharp
using System;
using System.IdentityModel.Tokens.Jwt;
using System.Security.Claims;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Authentication;
using Microsoft.AspNetCore.Authentication.Cookies;
using Microsoft.AspNetCore.Authentication.OpenIdConnect;
using Microsoft.AspNetCore.Builder;
using Microsoft.AspNetCore.Diagnostics;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;
using Microsoft.IdentityModel.Tokens;

var builder = WebApplication.CreateBuilder(args);
var config = builder.Configuration;
var env = builder.Environment;

// Logging
builder.Logging.ClearProviders();
builder.Logging.AddConsole();

// Session for correlation / nonce if needed
builder.Services.AddDistributedMemoryCache();
builder.Services.AddSession();

// Authentication configuration
builder.Services
    .AddAuthentication(options =>
    {
        options.DefaultScheme = CookieAuthenticationDefaults.AuthenticationScheme;
        options.DefaultChallengeScheme = OpenIdConnectDefaults.AuthenticationScheme;
    })
    .AddCookie(options =>
    {
        options.Cookie.HttpOnly = true;
        options.Cookie.SecurePolicy = env.IsDevelopment()
            ? CookieSecurePolicy.SameAsRequest
            : CookieSecurePolicy.Always;
        options.Cookie.SameSite = SameSiteMode.Strict;
        options.SlidingExpiration = true;
        options.Events = new CookieAuthenticationEvents
        {
            OnValidatePrincipal = context =>
            {
                // DEFENSE: Optionally re-validate against IdP or check revocation store
                return Task.CompletedTask;
            }
        };
    })
    .AddOpenIdConnect(OpenIdConnectDefaults.AuthenticationScheme, options =>
    {
        options.Authority = config["OIDC:Authority"]!; // e.g. https://login.microsoftonline.com/tenant/v2.0
        options.ClientId = config["OIDC:ClientId"]!;
        options.ClientSecret = config["OIDC:ClientSecret"]!;
        options.ResponseType = "code"; // Authorization Code flow
        options.SaveTokens = false; // Don't persist tokens needlessly

        // PRIMARY DEFENSE: strict token validation
        options.TokenValidationParameters = new TokenValidationParameters
        {
            ValidateIssuer = true,
            ValidIssuer = config["OIDC:Issuer"],
            ValidateAudience = true,
            ValidAudience = config["OIDC:ClientId"],
            ValidateLifetime = true,
            ClockSkew = TimeSpan.FromMinutes(2),
            ValidateIssuerSigningKey = true
        };

        options.CallbackPath = "/signin-oidc";
        options.SignedOutCallbackPath = "/signout-callback-oidc";

        // DEFENSE: built-in nonce & correlation checks for replay/CSRF
        options.UseTokenLifetime = false;

        options.Events = new OpenIdConnectEvents
        {
            OnTokenValidated = context =>
            {
                var logger = context.HttpContext.RequestServices
                    .GetRequiredService<ILoggerFactory>()
                    .CreateLogger("OIDC");

                var subject = context.Principal?.FindFirst(ClaimTypes.NameIdentifier)?.Value;
                logger.LogInformation("OIDC token validated for subject {Sub}", subject);

                // Add extra claims or perform additional checks if needed
                return Task.CompletedTask;
            },
            OnAuthenticationFailed = context =>
            {
                var logger = context.HttpContext.RequestServices
                    .GetRequiredService<ILoggerFactory>()
                    .CreateLogger("OIDC");
                logger.LogWarning(context.Exception, "OIDC authentication failed");

                context.HandleResponse();
                context.Response.StatusCode = StatusCodes.Status401Unauthorized;
                return context.Response.WriteAsync("Authentication failed.");
            },
            OnRedirectToIdentityProvider = context =>
            {
                // RATE LIMIT / MONITOR login attempts by IP
                var httpContext = context.HttpContext;
                var logger = httpContext.RequestServices
                    .GetRequiredService<ILoggerFactory>()
                    .CreateLogger("OIDC");

                logger.LogInformation("Redirecting to IdP for login from {IP}",
                    httpContext.Connection.RemoteIpAddress?.ToString());

                // Example: store original returnUrl securely
                var returnUrl = httpContext.Request.Query["returnUrl"].ToString();
                if (!string.IsNullOrEmpty(returnUrl) && httpContext.RequestServices
                        .GetRequiredService<LinkGenerator>().GetPathByAction("Index", "Home") != null
                    && httpContext.RequestServices
                        .GetRequiredService<LinkGenerator>().IsLocalUrl(returnUrl))
                {
                    httpContext.Session.SetString("returnUrl", returnUrl);
                }

                return Task.CompletedTask;
            },
            OnRedirectToIdentityProviderForSignOut = context =>
            {
                // Optional: audit logout
                var logger = context.HttpContext.RequestServices
                    .GetRequiredService<ILoggerFactory>()
                    .CreateLogger("OIDC");
                logger.LogInformation("User signing out, redirecting to IdP");
                return Task.CompletedTask;
            }
        };
    });

builder.Services.AddAuthorization();
builder.Services.AddControllersWithViews();

var app = builder.Build();

// Global error handler with no sensitive leaks
app.UseExceptionHandler(errorApp =>
{
    errorApp.Run(async context =>
    {
        var exceptionFeature = context.Features.Get<IExceptionHandlerFeature>();
        var logger = context.RequestServices
            .GetRequiredService<ILoggerFactory>()
            .CreateLogger("GlobalException");
        logger.LogError(exceptionFeature?.Error, "Unhandled exception");

        context.Response.StatusCode = StatusCodes.Status500InternalServerError;
        await context.Response.WriteAsync("An unexpected error occurred.");
    });
});

// Security headers
app.Use(async (ctx, next) =>
{
    ctx.Response.Headers["X-Content-Type-Options"] = "nosniff";
    ctx.Response.Headers["X-Frame-Options"] = "DENY";
    ctx.Response.Headers["X-XSS-Protection"] = "0";
    ctx.Response.Headers["Content-Security-Policy"] = "default-src 'self'";
    await next();
});

app.UseHttpsRedirection();
app.UseSession();
app.UseAuthentication();
app.UseAuthorization();

app.MapGet("/login", async context =>
{
    // Central login endpoint – could be wrapped with custom rate limiting middleware
    await context.ChallengeAsync(OpenIdConnectDefaults.AuthenticationScheme,
        new AuthenticationProperties { RedirectUri = "/" });
});

app.MapGet("/logout", async context =>
{
    await context.SignOutAsync(CookieAuthenticationDefaults.AuthenticationScheme);
    await context.SignOutAsync(OpenIdConnectDefaults.AuthenticationScheme,
        new AuthenticationProperties { RedirectUri = "/" });
});

app.MapControllers();

app.Run();
```

**Defense in Depth Layers**:
1. **Protocol & Token Validation Layer**
   - The OpenID Connect middleware enforces issuer, audience, lifetime, and signature checks via `TokenValidationParameters`, mitigating forgery and token replay.
   ```csharp
   options.TokenValidationParameters = new TokenValidationParameters
   {
       ValidateIssuer = true,
       ValidIssuer = config["OIDC:Issuer"],
       ValidateAudience = true,
       ValidAudience = config["OIDC:ClientId"],
       ValidateLifetime = true,
       ValidateIssuerSigningKey = true
   };
   ```
2. **Session & Cookie Security Layer**
   - Hardened cookies (`HttpOnly`, `Secure`, `SameSite`) and optional principal re-validation protect against theft and misuse of the local session.
   ```csharp
   options.Cookie.HttpOnly = true;
   options.Cookie.SecurePolicy = CookieSecurePolicy.Always;
   options.Cookie.SameSite = SameSiteMode.Strict;
   ```
3. **Monitoring, Rate Limiting & Error Handling Layer**
   - Login redirects are logged with IP; global exception handler prevents leaking details; you can plug in middleware for rate limiting sensitive endpoints.
   ```csharp
   options.Events.OnRedirectToIdentityProvider = context =>
   {
       var logger = context.HttpContext.RequestServices
           .GetRequiredService<ILoggerFactory>()
           .CreateLogger("OIDC");
       logger.LogInformation("Redirecting to IdP for login from {IP}",
           context.HttpContext.Connection.RemoteIpAddress?.ToString());
       return Task.CompletedTask;
   };
   ```

**Additional Protections**:
- **Environment-specific configuration**: Use different `Authority`, `ClientId`, `ClientSecret`, and cookie settings for dev/test/prod to avoid cross-environment token confusion.
- **Audit logging**: Log successful and failed authentication events with subject, IP, and correlation IDs; send to a SIEM for alerting on anomalies.
- **Rate limiting / lockout**: Apply rate limiting middleware and potentially step-up challenges (MFA) or lockouts for suspicious login patterns (multiple attempts, unusual IPs), further reducing the risk of token brute force or abuse.

Manually handling passwords and user lookup in ASP.NET Core while partially using Identity can easily create authentication bypasses and weak password handling.

**VULNERABLE CODE**:

```csharp
using System;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Data.SqlClient;
using System.Security.Cryptography;
using System.Text;

namespace MyApp.Controllers
{
    [Route("account")]
    public class AccountController : Controller
    {
        private const string ConnectionString = "Server=localhost;Database=MyApp;Trusted_Connection=True;";

        [HttpPost("login")]        
        public async Task<IActionResult> Login(string email, string password)
        {
            // Manually querying the database, bypassing ASP.NET Core Identity
            using var conn = new SqlConnection(ConnectionString);
            await conn.OpenAsync();

            var cmd = conn.CreateCommand();
            cmd.CommandText = $"SELECT Id, Email, PasswordHash FROM AspNetUsers WHERE Email = '{email}'";

            using var reader = await cmd.ExecuteReaderAsync();
            if (!await reader.ReadAsync())
            {
                return Unauthorized("Invalid credentials");
            }

            var storedHash = reader.GetString(2); // stored as plain SHA256 hex

            using var sha = SHA256.Create();
            var inputBytes = Encoding.UTF8.GetBytes(password);
            var inputHash = BitConverter.ToString(sha.ComputeHash(inputBytes)).Replace("-", string.Empty);

            if (storedHash == inputHash)
            {
                // No lockout, no sign-in manager, just issue an auth cookie
                Response.Cookies.Append("auth", reader.GetString(0));
                return Ok("Logged in");
            }

            return Unauthorized("Invalid credentials");
        }
    }
}
```

**Attack Payload** (SQL injection on email):
```sql
' OR '1'='1'--
```

This payload, used as the `email` value, turns the query into:
```sql
SELECT Id, Email, PasswordHash FROM AspNetUsers WHERE Email = '' OR '1'='1'--'
```
which returns the first user (often an admin). The code then only checks the password hash against the attacker's input; combined with implementation mistakes (e.g., comparing wrong columns, NULL checks, or logic bugs), this pattern commonly results in auth bypasses.

**Why This Is Dangerous**:
- Directly concatenates user input into SQL, allowing SQL injection and potential account takeover.
- Bypasses ASP.NET Core Identity's hardened password hashing (PBKDF2/Argon2), using raw SHA-256 without salt.
- Issues a home-grown auth cookie instead of using the Identity sign-in pipeline (no protection against tampering, no lockout, no security stamp validation).

**SECURE VERSION**:

```csharp
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Identity;
using Microsoft.Extensions.Logging;

namespace MyApp.Controllers
{
    public class ApplicationUser : IdentityUser
    {
    }

    [Route("account")]
    public class AccountController : Controller
    {
        private readonly SignInManager<ApplicationUser> _signInManager;
        private readonly UserManager<ApplicationUser> _userManager;
        private readonly ILogger<AccountController> _logger;

        public AccountController(
            SignInManager<ApplicationUser> signInManager,
            UserManager<ApplicationUser> userManager,
            ILogger<AccountController> logger)
        {
            _signInManager = signInManager;
            _userManager = userManager;
            _logger = logger;
        }

        public class LoginRequest
        {
            public string Email { get; set; } = string.Empty;
            public string Password { get; set; } = string.Empty;
            public bool RememberMe { get; set; }
        }

        [HttpPost("login")]
        public async Task<IActionResult> Login([FromBody] LoginRequest model)
        {
            if (!ModelState.IsValid)
            {
                return BadRequest("Invalid request");
            }

            // Primary defense: use ASP.NET Core Identity SignInManager
            var user = await _userManager.FindByEmailAsync(model.Email);
            if (user == null)
            {
                // Generic error to avoid user enumeration
                _logger.LogWarning("Login failed for non-existent email {Email}", model.Email);
                await Task.Delay(200); // small delay to reduce timing attacks
                return Unauthorized("Invalid credentials");
            }

            var result = await _signInManager.PasswordSignInAsync(
                user,
                model.Password,
                isPersistent: model.RememberMe,
                lockoutOnFailure: true);

            if (result.Succeeded)
            {
                _logger.LogInformation("User {UserId} logged in successfully", user.Id);
                return Ok("Logged in");
            }

            if (result.IsLockedOut)
            {
                _logger.LogWarning("User account {UserId} locked out due to failures", user.Id);
                return Unauthorized("Account locked. Try again later.");
            }

            _logger.LogWarning("Invalid login attempt for user {UserId}", user.Id);
            return Unauthorized("Invalid credentials");
        }
    }
}
```

**Key Security Controls**:
- Uses `SignInManager` and `UserManager`, which rely on parameterized queries and hardened password hashing algorithms (PBKDF2 by default) instead of manual SQL and weak hashes.
- Enables account lockout (`lockoutOnFailure: true`), throttling brute-force attempts and providing safe, generic responses to avoid user enumeration.
- Centralizes authentication in the ASP.NET Core Identity pipeline, which issues signed, protected cookies and supports security stamps, two-factor auth, and revocation instead of custom cookie handling.

For production, you want a layered approach: hardened Identity options, proper error handling and logging, rate limiting/brute-force protection, and environment-specific security settings.

**PRODUCTION PATTERN**:

```csharp
using System;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Identity;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;

namespace MyApp.Controllers
{
    public class ApplicationUser : IdentityUser
    {
    }

    public class LoginRequest
    {
        public string Email { get; set; } = string.Empty;
        public string Password { get; set; } = string.Empty;
        public bool RememberMe { get; set; }
        public string? TwoFactorCode { get; set; }
    }

    [AllowAnonymous]
    [Route("api/account")]
    [ApiController]
    public class AccountController : ControllerBase
    {
        private readonly SignInManager<ApplicationUser> _signInManager;
        private readonly UserManager<ApplicationUser> _userManager;
        private readonly ILogger<AccountController> _logger;
        private readonly IConfiguration _configuration;

        public AccountController(
            SignInManager<ApplicationUser> signInManager,
            UserManager<ApplicationUser> userManager,
            ILogger<AccountController> logger,
            IConfiguration configuration)
        {
            _signInManager = signInManager;
            _userManager = userManager;
            _logger = logger;
            _configuration = configuration;
        }

        [HttpPost("login")]
        public async Task<IActionResult> Login([FromBody] LoginRequest model)
        {
            if (!ModelState.IsValid)
            {
                _logger.LogWarning("Invalid login model from {Ip}", HttpContext.Connection.RemoteIpAddress);
                return BadRequest("Invalid request");
            }

            try
            {
                var user = await _userManager.FindByEmailAsync(model.Email);
                if (user == null)
                {
                    await Task.Delay(200);
                    _logger.LogWarning("Login failed for non-existent email from {Ip}", HttpContext.Connection.RemoteIpAddress);
                    return Unauthorized("Invalid credentials");
                }

                // Primary auth attempt
                var result = await _signInManager.CheckPasswordSignInAsync(
                    user,
                    model.Password,
                    lockoutOnFailure: true);

                if (result.IsLockedOut)
                {
                    _logger.LogWarning("Locked-out user {UserId} attempted login from {Ip}", user.Id, HttpContext.Connection.RemoteIpAddress);
                    return Unauthorized("Account locked. Try again later.");
                }

                if (!result.Succeeded && !result.RequiresTwoFactor)
                {
                    _logger.LogWarning("Invalid password for user {UserId} from {Ip}", user.Id, HttpContext.Connection.RemoteIpAddress);
                    return Unauthorized("Invalid credentials");
                }

                // Two-factor flow
                if (result.RequiresTwoFactor)
                {
                    if (string.IsNullOrWhiteSpace(model.TwoFactorCode))
                    {
                        _logger.LogInformation("2FA required for user {UserId}", user.Id);
                        return Unauthorized("Two-factor authentication required.");
                    }

                    var twoFactorResult = await _signInManager.TwoFactorAuthenticatorSignInAsync(
                        model.TwoFactorCode,
                        isPersistent: model.RememberMe,
                        rememberClient: true);

                    if (!twoFactorResult.Succeeded)
                    {
                        _logger.LogWarning("Invalid 2FA code for user {UserId} from {Ip}", user.Id, HttpContext.Connection.RemoteIpAddress);
                        return Unauthorized("Invalid credentials");
                    }

                    _logger.LogInformation("User {UserId} logged in with 2FA", user.Id);
                    return Ok("Logged in with 2FA");
                }

                // Successful password-only sign in (2FA not required for this user)
                await _signInManager.SignInAsync(user, isPersistent: model.RememberMe);
                _logger.LogInformation("User {UserId} logged in successfully from {Ip}", user.Id, HttpContext.Connection.RemoteIpAddress);
                return Ok("Logged in");
            }
            catch (Exception ex)
            {
                // Fail securely: generic response, detailed log
                _logger.LogError(ex, "Unhandled error during login for email {Email} from {Ip}",
                    model.Email, HttpContext.Connection.RemoteIpAddress);
                return StatusCode(500, "An error occurred.");
            }
        }
    }

    public static class IdentityConfig
    {
        public static void ConfigureIdentity(IdentityOptions options, bool isProduction)
        {
            // Password strength
            options.Password.RequireDigit = true;
            options.Password.RequireLowercase = true;
            options.Password.RequireUppercase = true;
            options.Password.RequireNonAlphanumeric = true;
            options.Password.RequiredLength = isProduction ? 12 : 8;

            // Lockout settings
            options.Lockout.DefaultLockoutTimeSpan = TimeSpan.FromMinutes(isProduction ? 15 : 2);
            options.Lockout.MaxFailedAccessAttempts = isProduction ? 5 : 10;
            options.Lockout.AllowedForNewUsers = true;

            // User
            options.User.RequireUniqueEmail = true;

            // Sign-in
            options.SignIn.RequireConfirmedEmail = isProduction;
        }
    }
}
```

**Defense in Depth Layers**:
1. **Framework-based authentication & 2FA**:
   - Uses `CheckPasswordSignInAsync`, `SignInAsync`, and `TwoFactorAuthenticatorSignInAsync` so all password hashing, cookie creation, and security stamp handling are done by ASP.NET Core Identity instead of custom code.
2. **Lockout, throttling, and environment-specific hardening**:
   - `IdentityConfig.ConfigureIdentity` enforces strong passwords, lockout thresholds, and email confirmation with tighter settings in production than in development.
3. **Robust logging and secure error handling**:
   - Structured logging for failed and successful attempts (`_logger.LogWarning`, `_logger.LogInformation`, `_logger.LogError`) including user ID and IP, while returning only generic messages to clients to avoid information disclosure.

**Additional Protections**:
- Configure authentication cookies in `Program.cs` / `Startup`:
  - Set `Cookie.SecurePolicy = CookieSecurePolicy.Always`, `HttpOnly = true`, and `SameSite = SameSiteMode.Strict` or `Lax` in production.
- Add rate limiting at the API gateway or middleware level (e.g., "5 login attempts per minute per IP") to reduce credential stuffing and password spraying.
- Enable centralized monitoring and alerting (e.g., Application Insights, ELK, SIEM) on suspicious patterns such as repeated lockouts, login attempts from new countries, or 2FA failures to quickly detect and respond to attacks.

JWT bearer authentication can become very dangerous if you skip or misconfigure signature and claim validation. Below is an example of an insecure implementation and then a hardened one.

**VULNERABLE CODE**:

```csharp
using System;
using System.IdentityModel.Tokens.Jwt;
using System.Security.Claims;
using Microsoft.AspNetCore.Builder;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.DependencyInjection;

var builder = WebApplication.CreateBuilder(args);

// VULNERABLE: Manually parse JWT without verifying signature or claims
builder.Services.AddAuthentication("Bearer").AddJwtBearer("Bearer", options =>
{
    // Misconfiguration: Do not validate anything, accept all tokens
    options.RequireHttpsMetadata = false; // bad for production
    options.Events = new Microsoft.AspNetCore.Authentication.JwtBearer.JwtBearerEvents
    {
        OnMessageReceived = context =>
        {
            // Just grab the token without any checks
            var token = context.Request.Headers["Authorization"].ToString().Replace("Bearer ", "");
            context.Token = token;
            return System.Threading.Tasks.Task.CompletedTask;
        },
        OnTokenValidated = context =>
        {
            // Blindly trust parsed token, no signature validation enforced
            var handler = new JwtSecurityTokenHandler();
            var jwt = handler.ReadJwtToken(context.SecurityToken.RawData);

            // Directly use claims without verifying issuer/audience/expiration
            var identity = new ClaimsIdentity(jwt.Claims, "Bearer");
            context.Principal = new ClaimsPrincipal(identity);
            return System.Threading.Tasks.Task.CompletedTask;
        }
    };
});

var app = builder.Build();

app.UseAuthentication();
app.UseAuthorization();

app.MapGet("/api/admin", (ClaimsPrincipal user) =>
{
    // Assumes role claim is trustworthy
    if (user.IsInRole("admin"))
    {
        return Results.Ok("Top secret admin data");
    }

    return Results.Forbid();
});

app.Run();
```

**Attack Payload**:
```text
// Attacker crafts an unsigned JWT or one signed with their own key
// Header:
{"alg":"none","typ":"JWT"}

// Payload:
{"sub":"attacker","role":"admin","exp":4102444800}

// Resulting token (base64url-encoded, no signature):
eyJhbGciOiJub25lIiwidHlwIjoiSldUIn0.eyJzdWIiOiJhdHRhY2tlciIsInJvbGUiOiJhZG1pbiIsImV4cCI6NDEwMjQ0NDgwMH0.

// Sent as HTTP header:
Authorization: Bearer eyJhbGciOiJub25lIiwidHlwIjoiSldUIn0.eyJzdWIiOiJhdHRhY2tlciIsInJvbGUiOiJhZG1pbiIsImV4cCI6NDEwMjQ0NDgwMH0.
```

**Why This Is Dangerous**:
- Skips cryptographic signature verification entirely, so anyone can forge tokens and set arbitrary roles like `admin`.
- Does not validate issuer, audience, or expiration, allowing tokens from other systems or expired tokens to be accepted.
- Disables HTTPS requirement, making tokens vulnerable to interception and replay on the wire.

**SECURE VERSION**:

```csharp
using System;
using System.IdentityModel.Tokens.Jwt;
using System.Security.Claims;
using System.Text;
using Microsoft.AspNetCore.Authentication.JwtBearer;
using Microsoft.AspNetCore.Builder;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using Microsoft.IdentityModel.Tokens;

var builder = WebApplication.CreateBuilder(args);

// Strong symmetric key for demo; in production use Key Vault / environment secrets
var jwtKey = builder.Configuration["Jwt:SigningKey"] ?? "CHANGE_ME_TO_A_LONG_RANDOM_SECRET";
var signingKey = new SymmetricSecurityKey(Encoding.UTF8.GetBytes(jwtKey));

builder.Services.AddAuthentication(options =>
{
    options.DefaultAuthenticateScheme = JwtBearerDefaults.AuthenticationScheme;
    options.DefaultChallengeScheme = JwtBearerDefaults.AuthenticationScheme;
}).AddJwtBearer(options =>
{
    options.RequireHttpsMetadata = true; // enforce HTTPS in production
    options.SaveToken = false;

    options.TokenValidationParameters = new TokenValidationParameters
    {
        ValidateIssuerSigningKey = true,
        IssuerSigningKey = signingKey,

        ValidateIssuer = true,
        ValidIssuer = builder.Configuration["Jwt:Issuer"] ?? "https://auth.mycompany.com",

        ValidateAudience = true,
        ValidAudience = builder.Configuration["Jwt:Audience"] ?? "my-api",

        ValidateLifetime = true,
        ClockSkew = TimeSpan.FromMinutes(2), // small clock skew

        RequireExpirationTime = true,
        RequireSignedTokens = true,
        RoleClaimType = ClaimTypes.Role,
        NameClaimType = ClaimTypes.NameIdentifier
    };

    options.Events = new JwtBearerEvents
    {
        OnAuthenticationFailed = context =>
        {
            var logger = context.HttpContext.RequestServices
                .GetRequiredService<ILoggerFactory>()
                .CreateLogger("JwtAuth");
            logger.LogWarning(context.Exception, "JWT authentication failed from {IP}",
                context.HttpContext.Connection.RemoteIpAddress);
            return System.Threading.Tasks.Task.CompletedTask;
        },
        OnTokenValidated = context =>
        {
            // Additional custom checks (defense in depth)
            var principal = context.Principal;
            var logger = context.HttpContext.RequestServices
                .GetRequiredService<ILoggerFactory>()
                .CreateLogger("JwtAuth");

            if (principal == null || !principal.Identity!.IsAuthenticated)
            {
                context.Fail("Unauthenticated principal");
                return System.Threading.Tasks.Task.CompletedTask;
            }

            // Example: ensure "role" claim is present for admin endpoints
            var roleClaims = principal.FindAll(ClaimTypes.Role);
            if (roleClaims == null)
            {
                logger.LogWarning("Token validated but no role claims found for {User}",
                    principal.Identity!.Name ?? "unknown");
            }

            return System.Threading.Tasks.Task.CompletedTask;
        }
    };
});

builder.Services.AddAuthorization(options =>
{
    options.AddPolicy("RequireAdmin", policy =>
        policy.RequireAuthenticatedUser().RequireRole("admin"));
});

var app = builder.Build();

if (!app.Environment.IsDevelopment())
{
    app.UseHsts();
}

app.UseHttpsRedirection();
app.UseAuthentication();
app.UseAuthorization();

app.MapGet("/api/admin", (ClaimsPrincipal user) =>
{
    // Only reachable if JWT is valid and user has admin role
    return Results.Ok(new
    {
        message = "Top secret admin data",
        user = user.Identity?.Name ?? "unknown"
    });
}).RequireAuthorization("RequireAdmin");

app.MapGet("/api/health", () => Results.Ok("OK"));

app.Run();
```

**Key Security Controls**:
- **Signature & token validation**: `ValidateIssuerSigningKey`, `RequireSignedTokens`, and a strong `IssuerSigningKey` ensure only tokens signed by your trusted key are accepted.
- **Claim & lifetime validation**: `ValidateIssuer`, `ValidateAudience`, `ValidateLifetime`, and `RequireExpirationTime` prevent use of tokens from other issuers, other audiences, or expired/replayed tokens.
- **Defense in depth & secure transport**: `RequireHttpsMetadata`, HTTPS redirection, authorization policies, and structured logging provide layered protection, monitoring, and least privilege.

In production, you need a more advanced JWT setup: key rotation, support for multiple trusted issuers, replay protection for critical operations, and rate limiting around authentication flows. Here’s a pattern that combines these.

**PRODUCTION PATTERN**:

```csharp
using System;
using System.Collections.Concurrent;
using System.IdentityModel.Tokens.Jwt;
using System.Linq;
using System.Security.Claims;
using System.Text;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Authentication.JwtBearer;
using Microsoft.AspNetCore.Builder;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;
using Microsoft.IdentityModel.Tokens;

var builder = WebApplication.CreateBuilder(args);

// ENV-SPECIFIC CONFIGURATION
var env = builder.Environment;
var configuration = builder.Configuration;

// Example key set for rotation (in reality use Azure Key Vault, AWS KMS, or JWKS)
var activeKeyId = configuration["Jwt:ActiveKeyId"] ?? "key-2025-01";
var keys = new ConcurrentDictionary<string, SecurityKey>();
keys["key-2024-12"] = new SymmetricSecurityKey(Encoding.UTF8.GetBytes(configuration["Jwt:Key_2024_12"] ?? "OLD_LONG_SECRET"));
keys["key-2025-01"] = new SymmetricSecurityKey(Encoding.UTF8.GetBytes(configuration["Jwt:Key_2025_01"] ?? "CURRENT_LONG_SECRET"));

// Multiple issuers (external IdP + internal STS)
var validIssuers = new[]
{
    configuration["Jwt:InternalIssuer"] ?? "https://auth.internal.local",
    configuration["Jwt:ExternalIssuer"] ?? "https://login.microsoftonline.com/tenant-id/v2.0"
};

var validAudiences = new[]
{
    configuration["Jwt:ApiAudience"] ?? "my-production-api"
};

builder.Services.AddSingleton<IDictionary<string, SecurityKey>>(keys);

builder.Services.AddAuthentication(options =>
{
    options.DefaultAuthenticateScheme = JwtBearerDefaults.AuthenticationScheme;
    options.DefaultChallengeScheme = JwtBearerDefaults.AuthenticationScheme;
})
.AddJwtBearer(options =>
{
    options.RequireHttpsMetadata = !env.IsDevelopment();
    options.SaveToken = false;

    options.TokenValidationParameters = new TokenValidationParameters
    {
        RequireSignedTokens = true,
        ValidateIssuerSigningKey = true,

        // Use IssuerSigningKeyResolver to support key rotation (kid header)
        IssuerSigningKeyResolver = (token, securityToken, kid, parameters) =>
        {
            var logger = builder.Services.BuildServiceProvider()
                .GetRequiredService<ILoggerFactory>().CreateLogger("KeyResolver");

            if (kid != null && keys.TryGetValue(kid, out var key))
            {
                return new[] { key };
            }

            logger.LogWarning("Unknown key id {Kid} when validating token", kid);
            return Array.Empty<SecurityKey>();
        },

        ValidateIssuer = true,
        ValidIssuers = validIssuers,

        ValidateAudience = true,
        ValidAudiences = validAudiences,

        ValidateLifetime = true,
        ClockSkew = TimeSpan.FromMinutes(2),

        RoleClaimType = ClaimTypes.Role,
        NameClaimType = ClaimTypes.NameIdentifier
    };

    // EVENTS FOR LOGGING, REPLAY DEFENSE, AND RATE LIMITING
    // Simple in-memory replay cache for demo; production should use Redis or database
    var replayCache = new ConcurrentDictionary<string, DateTimeOffset>();

    options.Events = new JwtBearerEvents
    {
        OnMessageReceived = context =>
        {
            // Basic rate limiting by IP for auth endpoints (defense against brute-force)
            var path = context.HttpContext.Request.Path.Value ?? string.Empty;
            if (path.StartsWith("/api/login", StringComparison.OrdinalIgnoreCase))
            {
                // In real apps, integrate with a rate limiter (e.g. AspNetCoreRateLimit or gateway)
            }
            return Task.CompletedTask;
        },
        OnTokenValidated = context =>
        {
            var logger = context.HttpContext.RequestServices
                .GetRequiredService<ILoggerFactory>().CreateLogger("JwtAuth");
            var principal = context.Principal;
            var jwtToken = context.SecurityToken as JwtSecurityToken;

            if (jwtToken == null)
            {
                context.Fail("Invalid token type");
                return Task.CompletedTask;
            }

            // REPLAY PROTECTION (for sensitive operations)
            var jti = jwtToken.Id;
            if (!string.IsNullOrEmpty(jti))
            {
                var expires = jwtToken.ValidTo == DateTime.MinValue
                    ? DateTimeOffset.UtcNow.AddMinutes(15)
                    : jwtToken.ValidTo;

                if (!replayCache.TryAdd(jti, expires))
                {
                    logger.LogWarning("Replay detected for token jti {Jti} from {IP}",
                        jti, context.HttpContext.Connection.RemoteIpAddress);
                    context.Fail("Token replay detected");
                    return Task.CompletedTask;
                }
            }

            // CUSTOM CLAIM VALIDATION
            // Ensure token has expected audience for high-privilege endpoints
            var audience = jwtToken.Audiences.FirstOrDefault();
            if (string.IsNullOrEmpty(audience) || !validAudiences.Contains(audience))
            {
                logger.LogWarning("Token with invalid audience {Audience} from {IP}",
                    audience ?? "<none>", context.HttpContext.Connection.RemoteIpAddress);
                context.Fail("Invalid audience");
                return Task.CompletedTask;
            }

            // Audit log for successful validation (sample)
            logger.LogInformation("JWT validated for user {User} with roles {Roles}",
                principal?.Identity?.Name ?? "unknown",
                string.Join(',', principal?.FindAll(ClaimTypes.Role).Select(r => r.Value) ?? Array.Empty<string>()));

            return Task.CompletedTask;
        },
        OnAuthenticationFailed = context =>
        {
            var logger = context.HttpContext.RequestServices
                .GetRequiredService<ILoggerFactory>().CreateLogger("JwtAuth");
            logger.LogWarning(context.Exception, "JWT authentication failed from {IP}",
                context.HttpContext.Connection.RemoteIpAddress);
            return Task.CompletedTask;
        },
        OnChallenge = context =>
        {
            // Prevent leaking details
            context.HandleResponse();
            context.Response.StatusCode = StatusCodes.Status401Unauthorized;
            context.Response.ContentType = "application/json";
            return context.Response.WriteAsync("{\"error\":\"unauthorized\"}");
        }
    };
});

