using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;
using Microsoft.IdentityModel.Tokens;

namespace MyApp.Controllers
{
    public interface ITotpService
    {
        bool VerifyCode(string secret, string code, int allowedDriftSteps = 1);
    }

    [ApiController]
    [Route("api/auth")]    
    public class ProdAuthController : ControllerBase
    {
        private readonly ILogger<ProdAuthController> _logger;
        private readonly IConfiguration _config;
        private readonly ITotpService _totpService;

        public ProdAuthController(
            ILogger<ProdAuthController> logger,
            IConfiguration config,
            ITotpService totpService)
        {
            _logger = logger;
            _config = config;
            _totpService = totpService;
        }

        [HttpPost("login")]
        [AllowAnonymous]
        public IActionResult Login([FromForm] string username, [FromForm] string password)
        {
            // 1. Primary authentication (hash + salt in production)
            if (!ValidateUserPassword(username, password))
            {
                _logger.LogWarning("Invalid primary login for {User} from {IP}", username, HttpContext.Connection.RemoteIpAddress);
                return Unauthorized("Invalid credentials");
            }

            // 2. Check if MFA is enrolled
            var mfaSecret = GetUserTotpSecret(username);
            if (string.IsNullOrEmpty(mfaSecret))
            {
                _logger.LogWarning("User {User} without MFA attempted login", username);
                return StatusCode(StatusCodes.Status403Forbidden, "MFA required. Please enroll.");
            }

            // 3. Issue short-lived MFA challenge token (no full session yet)
            var mfaToken = IssueMfaChallengeToken(username);

            _logger.LogInformation("MFA challenge issued for {User} from {IP}", username, HttpContext.Connection.RemoteIpAddress);
            return Ok(new { mfa_token = mfaToken, message = "Enter your authenticator app code." });
        }

        [HttpPost("verify-mfa")]
        [AllowAnonymous]
        public IActionResult VerifyMfa([FromForm] string mfaToken, [FromForm] string code)
        {
            var principal = ValidateMfaChallengeToken(mfaToken);
            if (principal == null)
            {
                _logger.LogWarning("Invalid or expired MFA token from {IP}", HttpContext.Connection.RemoteIpAddress);
                return Unauthorized("Invalid or expired MFA session");
            }

            var username = principal.FindFirst(ClaimTypes.Name)?.Value;
            if (string.IsNullOrEmpty(username))
            {
                _logger.LogError("MFA token missing username claim");
                return Unauthorized("Invalid MFA token");
            }

            // Rate limiting should also be enforced at the API gateway or middleware layer

            var mfaSecret = GetUserTotpSecret(username);
            if (string.IsNullOrEmpty(mfaSecret))
            {
                _logger.LogError("MFA verification for user {User} without secret", username);
                return Unauthorized("MFA not configured");
            }

            if (!_totpService.VerifyCode(mfaSecret, code))
            {
                _logger.LogWarning("Invalid TOTP for {User} from {IP}", username, HttpContext.Connection.RemoteIpAddress);
                return Unauthorized("Invalid code");
            }

            // 4. Successful MFA – issue full session / JWT
            var accessToken = IssueAccessToken(username);

            _logger.LogInformation("User {User} successfully completed MFA from {IP}", username, HttpContext.Connection.RemoteIpAddress);
            return Ok(new { access_token = accessToken });
        }

        private bool ValidateUserPassword(string username, string password)
        {
            // Placeholder; integrate with your identity store
            return username == "admin" && password == "P@ssw0rd";
        }

        private string GetUserTotpSecret(string username)
        {
            // In production, retrieve encrypted TOTP secret from DB
            if (username == "admin")
            {
                return "BASE32ENCODEDSECRET"; // placeholder
            }

            return string.Empty;
        }

        private string IssueMfaChallengeToken(string username)
        {
            var key = new SymmetricSecurityKey(Encoding.UTF8.GetBytes(_config["Jwt:MfaKey"]!));
            var creds = new SigningCredentials(key, SecurityAlgorithms.HmacSha256);

            var token = new JwtSecurityToken(
                issuer: _config["Jwt:Issuer"],
                audience: _config["Jwt:Audience"],
                claims: new[] { new Claim(ClaimTypes.Name, username) },
                expires: DateTime.UtcNow.AddMinutes(5),
                signingCredentials: creds);

            return new JwtSecurityTokenHandler().WriteToken(token);
        }

        private ClaimsPrincipal? ValidateMfaChallengeToken(string token)
        {
            try
            {
                var handler = new JwtSecurityTokenHandler();
                var principal = handler.ValidateToken(token, new TokenValidationParameters
                {
                    ValidateIssuer = true,
                    ValidateAudience = true,
                    ValidateIssuerSigningKey = true,
                    ValidIssuer = _config["Jwt:Issuer"],
                    ValidAudience = _config["Jwt:Audience"],
                    IssuerSigningKey = new SymmetricSecurityKey(Encoding.UTF8.GetBytes(_config["Jwt:MfaKey"]!)),
                    ClockSkew = TimeSpan.FromSeconds(30)
                }, out _);

                return principal;
            }
            catch (Exception ex)
            {
                _logger.LogWarning(ex, "Failed to validate MFA token");
                return null;
            }
        }

        private string IssueAccessToken(string username)
        {
            var key = new SymmetricSecurityKey(Encoding.UTF8.GetBytes(_config["Jwt:AccessKey"]!));
            var creds = new SigningCredentials(key, SecurityAlgorithms.HmacSha256);

            var claims = new[]
            {
                new Claim(ClaimTypes.Name, username),
                new Claim("mfa", "true")
            };

            var token = new JwtSecurityToken(
                issuer: _config["Jwt:Issuer"],
                audience: _config["Jwt:Audience"],
                claims: claims,
                expires: DateTime.UtcNow.AddMinutes(_config.GetValue<int>("Jwt:AccessTokenMinutes")),
                signingCredentials: creds);

            return new JwtSecurityTokenHandler().WriteToken(token);
        }
    }
}
```

**Defense in Depth Layers**:
1. **Environment-specific hardening**
   - Configure secrets and strict cookie/JWT settings only in production:
   ```csharp
   // In Program.cs / Startup.cs
   if (builder.Environment.IsProduction())
   {
       builder.Services.ConfigureApplicationCookie(options =>
       {
           options.Cookie.HttpOnly = true;
           options.Cookie.SecurePolicy = CookieSecurePolicy.Always;
           options.Cookie.SameSite = SameSiteMode.Strict;
       });
   }
   ```
2. **Rate limiting and lockout policies**
   - Use middleware or an API gateway to throttle login and MFA endpoints:
   ```csharp
   // Pseudocode for per-IP + per-user rate limit
   // Apply strict limits on /api/auth/login and /api/auth/verify-mfa
   app.UseMiddleware<RateLimitingMiddleware>();
   ```
3. **Monitoring and anomaly detection**
   - Log detailed events for security analytics:
   ```csharp
   _logger.LogWarning("Multiple failed MFA attempts for {User} from {IP}", user, ip);
   // Feed logs into SIEM to alert on spikes, impossible travel, or MFA fatigue patterns.
   ```

**Additional Protections**:
- Enroll MFA using secure flows (e.g., QR codes with TOTP secret, confirmed by password + second factor) and store secrets encrypted with a KMS.
- Use security headers such as `Strict-Transport-Security`, `X-Content-Type-Options`, and `Content-Security-Policy` to protect the web front-end that drives the MFA UX.
- Implement robust fallback and recovery: require strong identity proofing for MFA reset, notify users on new device enrollment, and log & alert on any MFA method changes.

When integrating OAuth 2.0 / OpenID Connect, many apps validate tokens incorrectly: they trust any JWT that looks valid, skip issuer/audience checks, ignore nonce, or don't verify signatures correctly. This can lead to account takeover.

**VULNERABLE CODE**:

```csharp
using System;
using System.IdentityModel.Tokens.Jwt;
using System.Security.Claims;
using Microsoft.AspNetCore.Mvc;

namespace MyApp.Controllers
{
    [Route("auth")]
    public class AuthController : Controller
    {
        [HttpPost("/oauth/callback")]
        public IActionResult OAuthCallback([FromForm] string id_token)
        {
            // VULNERABLE: Accepts any id_token string and just decodes it
            if (string.IsNullOrEmpty(id_token))
            {
                return BadRequest("Missing token");
            }

            var handler = new JwtSecurityTokenHandler();

            // VULNERABLE: Only reads payload, doesn't validate signature, issuer, audience or nonce
            var jwt = handler.ReadJwtToken(id_token);

            // VULNERABLE: Trusts the 'sub' and 'email' claims blindly
            string userId = jwt.Subject;
            string email = jwt.Payload["email"]?.ToString() ?? "unknown@example.com";

            // Create a claims identity from unvalidated token
            var identity = new ClaimsIdentity("oidc");
            identity.AddClaim(new Claim(ClaimTypes.NameIdentifier, userId));
            identity.AddClaim(new Claim(ClaimTypes.Email, email));

            HttpContext.User = new ClaimsPrincipal(identity);

            // No cookie security, no session binding
            return Redirect("/dashboard");
        }
    }
}
```

**Attack Payload** (attacker-supplied forged JWT ID token):
```text
// Header (base64):
{"alg":"none","typ":"JWT"}

// Payload (base64):
{
  "iss": "https://evil-idp.example.com/",
  "aud": "any-app",
  "sub": "attacker-account",
  "email": "victim@company.com",
  "exp": 1893456000
}

// Resulting token (concatenated, no signature):
<base64url(header)>.<base64url(payload)>.
```

**Why This Is Dangerous**:
- Accepts any `id_token` without verifying the cryptographic signature, allowing forged tokens (`alg: none` or fake keys).
- Does not check `iss` (issuer) or `aud` (audience), so tokens from another IdP or for another app are accepted.
- Ignores nonce and state, making it vulnerable to replay and CSRF attacks.

**SECURE VERSION**:

```csharp
using System;
using System.IdentityModel.Tokens.Jwt;
using System.Security.Claims;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Authentication;
using Microsoft.AspNetCore.Authentication.Cookies;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Configuration;
using Microsoft.IdentityModel.Protocols;
using Microsoft.IdentityModel.Protocols.OpenIdConnect;
using Microsoft.IdentityModel.Tokens;

namespace MyApp.Controllers
{
    [Route("auth")]
    public class AuthController : Controller
    {
        private readonly IConfiguration _configuration;
        private readonly IConfigurationManager<OpenIdConnectConfiguration> _configManager;

        public AuthController(IConfiguration configuration)
        {
            _configuration = configuration;

            string authority = _configuration["Oidc:Authority"]!; // e.g. https://login.microsoftonline.com/common/v2.0
            var documentRetriever = new HttpDocumentRetriever { RequireHttps = true };
            _configManager = new ConfigurationManager<OpenIdConnectConfiguration>(
                authority.TrimEnd('/') + "/.well-known/openid-configuration",
                new OpenIdConnectConfigurationRetriever(),
                documentRetriever);
        }

        [HttpPost("/oidc/callback")]
        [ValidateAntiForgeryToken]
        public async Task<IActionResult> OidcCallback([FromForm] string id_token, [FromForm] string state)
        {
            if (string.IsNullOrWhiteSpace(id_token))
            {
                return BadRequest("Missing id_token");
            }

            // Validate state (CSRF protection)
            var expectedState = HttpContext.Session.GetString("oidc_state");
            if (expectedState == null || !string.Equals(expectedState, state, StringComparison.Ordinal))
            {
                return Forbid();
            }

            OpenIdConnectConfiguration oidcConfig;
            try
            {
                oidcConfig = await _configManager.GetConfigurationAsync(HttpContext.RequestAborted);
            }
            catch (Exception ex)
            {
                // Log for monitoring, but don't leak details
                Console.Error.WriteLine($"OIDC config fetch failed: {ex.Message}");
                return StatusCode(503, "Authentication service unavailable");
            }

            var validationParameters = new TokenValidationParameters
            {
                ValidIssuer = oidcConfig.Issuer,
                ValidateIssuer = true,

                ValidAudience = _configuration["Oidc:ClientId"],
                ValidateAudience = true,

                IssuerSigningKeys = oidcConfig.SigningKeys,
                ValidateIssuerSigningKey = true,

                ValidateLifetime = true,
                ClockSkew = TimeSpan.FromMinutes(2)
            };

            ClaimsPrincipal principal;
            SecurityToken validatedToken;
            var handler = new JwtSecurityTokenHandler();

            try
            {
                principal = handler.ValidateToken(id_token, validationParameters, out validatedToken);
            }
            catch (SecurityTokenException ste)
            {
                Console.Error.WriteLine($"Invalid ID token: {ste.Message}");
                return Forbid();
            }
            catch (Exception ex)
            {
                Console.Error.WriteLine($"Token validation error: {ex.Message}");
                return StatusCode(500, "Authentication error");
            }

            // Optional: validate nonce to prevent replay
            var nonceClaim = principal.FindFirst("nonce");
            var expectedNonce = HttpContext.Session.GetString("oidc_nonce");
            if (nonceClaim == null || expectedNonce == null || !string.Equals(nonceClaim.Value, expectedNonce, StringComparison.Ordinal))
            {
                Console.Error.WriteLine("Nonce validation failed");
                return Forbid();
            }

            // Map expected claims only
            var nameId = principal.FindFirst(ClaimTypes.NameIdentifier)?.Value
                         ?? principal.FindFirst("sub")?.Value
                         ?? throw new InvalidOperationException("Missing subject claim");

            var email = principal.FindFirst(ClaimTypes.Email)?.Value
                        ?? principal.FindFirst("preferred_username")?.Value
                        ?? "unknown@example.com";

            var appIdentity = new ClaimsIdentity(CookieAuthenticationDefaults.AuthenticationScheme);
            appIdentity.AddClaim(new Claim(ClaimTypes.NameIdentifier, nameId));
            appIdentity.AddClaim(new Claim(ClaimTypes.Email, email));

            var authProperties = new AuthenticationProperties
            {
                IsPersistent = true,
                AllowRefresh = true,
                ExpiresUtc = DateTimeOffset.UtcNow.AddHours(8)
            };

            await HttpContext.SignInAsync(
                CookieAuthenticationDefaults.AuthenticationScheme,
                new ClaimsPrincipal(appIdentity),
                authProperties);

            Console.WriteLine($"User {nameId} signed in via OIDC at {DateTimeOffset.UtcNow:O}");

            return Redirect("/dashboard");
        }
    }
}
```

**Key Security Controls**:
- Validates the token using the IdP's OpenID Connect discovery document and signing keys, ensuring the signature, issuer, audience, and lifetime are all correct.
- Uses `state` and `nonce` to defend against CSRF and replay attacks, and binds the flow to the user's session.
- Uses cookie authentication with limited lifetime, secure session management, and logging for monitoring suspicious authentication failures.

In production with multiple OIDC providers, you want a unified authentication flow with provider-specific validation, strict configuration per environment, and strong monitoring. Centralize validation, clearly separate tenants/providers, and log every critical step.

**PRODUCTION PATTERN**:

```csharp
using System;
using System.Collections.Generic;
using System.IdentityModel.Tokens.Jwt;
using System.Linq;
using System.Security.Claims;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Authentication;
using Microsoft.AspNetCore.Authentication.Cookies;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;
using Microsoft.IdentityModel.Protocols;
using Microsoft.IdentityModel.Protocols.OpenIdConnect;
using Microsoft.IdentityModel.Tokens;

namespace MyApp.Controllers
{
    public class MultiOidcProvider
    {
        public string Name { get; set; } = string.Empty; // "azuread", "google"
        public string Authority { get; set; } = string.Empty;
        public string ClientId { get; set; } = string.Empty;
        public bool Enabled { get; set; } = true;
        public IConfigurationManager<OpenIdConnectConfiguration>? ConfigManager { get; set; }
    }

    [Route("auth")] 
    public class MultiAuthController : Controller
    {
        private readonly ILogger<MultiAuthController> _logger;
        private readonly IDictionary<string, MultiOidcProvider> _providers;
        private readonly JwtSecurityTokenHandler _jwtHandler = new JwtSecurityTokenHandler();

        public MultiAuthController(IConfiguration configuration, ILogger<MultiAuthController> logger)
        {
            _logger = logger;
            _providers = LoadProviders(configuration);
        }

        private IDictionary<string, MultiOidcProvider> LoadProviders(IConfiguration config)
        {
            var dict = new Dictionary<string, MultiOidcProvider>(StringComparer.OrdinalIgnoreCase);
            foreach (var section in config.GetSection("OidcProviders").GetChildren())
            {
                var provider = new MultiOidcProvider
                {
                    Name = section.Key,
                    Authority = section["Authority"]!,
                    ClientId = section["ClientId"]!,
                    Enabled = bool.Parse(section["Enabled"] ?? "true"),
                    ConfigManager = new ConfigurationManager<OpenIdConnectConfiguration>(
                        section["Authority"]!.TrimEnd('/') + "/.well-known/openid-configuration",
                        new OpenIdConnectConfigurationRetriever(),
                        new HttpDocumentRetriever { RequireHttps = true })
                };

                dict[provider.Name] = provider;
            }

            return dict;
        }

        [HttpGet("login/{provider}")]
        public IActionResult Login(string provider, string? returnUrl = null)
        {
            if (!_providers.TryGetValue(provider, out var p) || !p.Enabled)
            {
                _logger.LogWarning("Login attempt with unknown or disabled provider {Provider}", provider);
                return NotFound();
            }

            // Generate state & nonce per request
            string state = Guid.NewGuid().ToString("N");
            string nonce = Guid.NewGuid().ToString("N");

            HttpContext.Session.SetString($"oidc_state_{provider}", state);
            HttpContext.Session.SetString($"oidc_nonce_{provider}", nonce);
            HttpContext.Session.SetString("oidc_returnUrl", returnUrl ?? "/dashboard");

            // Build authorization request URL (simplified)
            string authUrl = $"{p.Authority.TrimEnd('/')}/authorize" +
                             $"?client_id={Uri.EscapeDataString(p.ClientId)}" +
                             $"&response_type=id_token" +
                             $"&scope=openid%20email%20profile" +
                             $"&redirect_uri={Uri.EscapeDataString(Url.ActionLink("Callback", "MultiAuth", new { provider }))}" +
                             $"&state={Uri.EscapeDataString(state)}" +
                             $"&nonce={Uri.EscapeDataString(nonce)}";

            _logger.LogInformation("Redirecting to OIDC provider {Provider} for login", provider);
            return Redirect(authUrl);
        }

        [HttpPost("callback/{provider}")]
        [ValidateAntiForgeryToken]
        public async Task<IActionResult> Callback(string provider, [FromForm] string id_token, [FromForm] string state)
        {
            if (!_providers.TryGetValue(provider, out var p) || !p.Enabled)
            {
                _logger.LogWarning("Callback from unknown or disabled provider {Provider}", provider);
                return NotFound();
            }

            var expectedState = HttpContext.Session.GetString($"oidc_state_{provider}");
            if (expectedState == null || !string.Equals(expectedState, state, StringComparison.Ordinal))
            {
                _logger.LogWarning("State mismatch for provider {Provider}. Possible CSRF.", provider);
                return Forbid();
            }

            var oidcConfig = await p.ConfigManager!.GetConfigurationAsync(HttpContext.RequestAborted);

            var validationParameters = new TokenValidationParameters
            {
                ValidIssuer = oidcConfig.Issuer,
                ValidateIssuer = true,
                ValidAudience = p.ClientId,
                ValidateAudience = true,
                IssuerSigningKeys = oidcConfig.SigningKeys,
                ValidateIssuerSigningKey = true,
                ValidateLifetime = true,
                ClockSkew = TimeSpan.FromMinutes(2)
            };

            try
            {
                ClaimsPrincipal externalPrincipal = _jwtHandler.ValidateToken(id_token, validationParameters, out _);

                string? nonce = externalPrincipal.FindFirst("nonce")?.Value;
                string? expectedNonce = HttpContext.Session.GetString($"oidc_nonce_{provider}");
                if (nonce == null || expectedNonce == null || !string.Equals(nonce, expectedNonce, StringComparison.Ordinal))
                {
                    _logger.LogWarning("Nonce validation failed for provider {Provider}", provider);
                    return Forbid();
                }

                string subject = externalPrincipal.FindFirst(ClaimTypes.NameIdentifier)?.Value
                               ?? externalPrincipal.FindFirst("sub")?.Value
                               ?? throw new SecurityTokenException("Missing subject");

                string email = externalPrincipal.FindFirst(ClaimTypes.Email)?.Value
                             ?? externalPrincipal.FindFirst("preferred_username")?.Value
                             ?? "unknown@example.com";

                // Map provider + subject to internal user (defense: no direct trust of email alone)
                string externalKey = provider + ":" + subject;
                string internalUserId = MapExternalToInternalUser(externalKey, email);

                var identity = new ClaimsIdentity(CookieAuthenticationDefaults.AuthenticationScheme);
                identity.AddClaim(new Claim(ClaimTypes.NameIdentifier, internalUserId));
                identity.AddClaim(new Claim("ext_provider", provider));
                identity.AddClaim(new Claim("ext_subject", subject));
                identity.AddClaim(new Claim(ClaimTypes.Email, email));

                var authProps = new AuthenticationProperties
                {
                    IsPersistent = true,
                    AllowRefresh = true,
                    ExpiresUtc = DateTimeOffset.UtcNow.AddHours(8)
                };

                await HttpContext.SignInAsync(
                    CookieAuthenticationDefaults.AuthenticationScheme,
                    new ClaimsPrincipal(identity),
                    authProps);

                _logger.LogInformation(
                    "User {UserId} signed in via {Provider} at {Time}",
                    internalUserId, provider, DateTimeOffset.UtcNow);

                string returnUrl = HttpContext.Session.GetString("oidc_returnUrl") ?? "/dashboard";
                return LocalRedirect(returnUrl);
            }
            catch (SecurityTokenException ste)
            {
                _logger.LogWarning(ste, "Invalid token from provider {Provider}", provider);
                return Forbid();
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Authentication error from provider {Provider}", provider);
                return StatusCode(StatusCodes.Status500InternalServerError, "Authentication error");
            }
        }

        private string MapExternalToInternalUser(string externalKey, string email)
        {
            // Production: look up mapping table; this is a placeholder
            // Ensure only pre-registered or allowed domains can log in
            if (!email.EndsWith("@mycompany.com", StringComparison.OrdinalIgnoreCase))
            {
                throw new SecurityTokenException("Unauthorized email domain");
            }

            // Deterministic pseudo-ID for demo purposes
            return "user-" + externalKey.GetHashCode().ToString("X");
        }
    }
}
```

**Defense in Depth Layers**:
1. **Strict Provider Configuration per Environment**: Using a config-driven `OidcProviders` section (different for dev/staging/prod) ensures only known authorities and client IDs are trusted. Example:
   ```csharp
   var provider = _providers[providerName];
   var validationParameters = new TokenValidationParameters
   {
       ValidIssuer = oidcConfig.Issuer,
       ValidAudience = provider.ClientId,
       IssuerSigningKeys = oidcConfig.SigningKeys
   };
   ```
2. **Session-Bound `state` and `nonce`**: Stored in server-side session and validated on callback to prevent CSRF and replay attacks.
   ```csharp
   HttpContext.Session.SetString($"oidc_state_{provider}", state);
   // ... later
   if (!string.Equals(expectedState, state, StringComparison.Ordinal))
   {
       return Forbid();
   }
   ```
3. **Internal User Mapping and Domain Filtering**: Maps `(provider, sub)` to an internal user ID and optionally enforces email domain restrictions to avoid trusting attacker-controlled identities.
   ```csharp
   if (!email.EndsWith("@mycompany.com", StringComparison.OrdinalIgnoreCase))
   {
       throw new SecurityTokenException("Unauthorized email domain");
   }
   ```

**Additional Protections**:
- Environment-specific cookie security (in `Startup`/`Program`): enable `Cookie.SecurePolicy = Always`, `HttpOnly`, and `SameSite=Strict` in production.
- Rate limiting login and callback endpoints (e.g., via ASP.NET Core middleware or API gateway) to deter brute force and token replay attempts.
- Centralized, structured logging & monitoring: feed `ILogger` output into SIEM (e.g., Azure Monitor, Splunk) with alerts on unusual provider errors, high failure rates, or logins from new geolocations.

Leaning too much on defaults and bypassing ASP.NET Core Identity's built‑in flows can introduce serious authentication issues, like user enumeration and weak session handling.

**VULNERABLE CODE**:

```csharp
using System;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Authentication.Cookies;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;

namespace MyApp.Controllers
{
    [Route("account")]
    public class AccountController : Controller
    {
        // Fake in-memory auth instead of ASP.NET Core Identity
        [HttpPost("login")]
        public async Task<IActionResult> Login(string username, string password)
        {
            // Insecure: leaking if a user exists
            if (username == "admin@example.com")
            {
                if (password == "P@ssw0rd")
                {
                    // Insecure: manual cookie without proper options
                    await HttpContext.Authentication.SignInAsync(
                        CookieAuthenticationDefaults.AuthenticationScheme,
                        new System.Security.Claims.ClaimsPrincipal(),
                        new Microsoft.AspNetCore.Authentication.AuthenticationProperties
                        {
                            IsPersistent = true, // long-lived cookie
                            ExpiresUtc = DateTimeOffset.UtcNow.AddDays(30)
                        });

                    return Redirect("/dashboard");
                }
                else
                {
                    return BadRequest("Wrong password for existing user.");
                }
            }

            return BadRequest("User does not exist.");
        }
    }
}
```

**Attack Payload** (credential stuffing / enumeration):

```text
username=admin@example.com&password=wrongpass
username=nonexistent@example.com&password=anything
```

- First request returns: `"Wrong password for existing user."`
- Second returns: `"User does not exist."`

This lets an attacker enumerate which accounts exist. Combined with long-lived cookies, successful guesses lead to persistent account takeover.

**Why This Is Dangerous**:
- Allows user enumeration via different error messages and timing behavior.
- Bypasses ASP.NET Core Identity's password hashing, lockout, and MFA mechanisms.
- Issues long-lived authentication cookies without secure flags or proper sign-in principal, making session hijacking and replay easier.

**SECURE VERSION**:

```csharp
using System;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Identity;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;

namespace MyApp.Controllers
{
    [Route("account")]
    [AllowAnonymous]
    public class AccountController : Controller
    {
        private readonly SignInManager<IdentityUser> _signInManager;
        private readonly UserManager<IdentityUser> _userManager;
        private readonly ILogger<AccountController> _logger;

        public AccountController(
            SignInManager<IdentityUser> signInManager,
            UserManager<IdentityUser> userManager,
            ILogger<AccountController> logger)
        {
            _signInManager = signInManager;
            _userManager = userManager;
            _logger = logger;
        }

        [HttpPost("login")]
        [ValidateAntiForgeryToken]
        public async Task<IActionResult> Login(string email, string password, bool rememberMe)
        {
            if (string.IsNullOrWhiteSpace(email) || string.IsNullOrWhiteSpace(password))
            {
                ModelState.AddModelError(string.Empty, "Invalid login attempt.");
                return BadRequest(ModelState);
            }

            // ASP.NET Core Identity handles hashing, lockout, timing, etc.
            var result = await _signInManager.PasswordSignInAsync(
                userName: email,
                password: password,
                isPersistent: rememberMe,
                lockoutOnFailure: true);

            if (result.Succeeded)
            {
                _logger.LogInformation("User {Email} logged in successfully.", email);
                return Ok(new { Message = "Logged in" });
            }

            if (result.IsLockedOut)
            {
                _logger.LogWarning("User account locked out: {Email}.", email);
                ModelState.AddModelError(string.Empty, "Account locked. Try again later.");
                return BadRequest(ModelState);
            }

            // Generic error message prevents user enumeration
            _logger.LogWarning("Invalid login attempt for {Email}.", email);
            ModelState.AddModelError(string.Empty, "Invalid login attempt.");
            return BadRequest(ModelState);
        }

        [HttpPost("logout")]
        [ValidateAntiForgeryToken]
        public async Task<IActionResult> Logout()
        {
            await _signInManager.SignOutAsync();
            _logger.LogInformation("User logged out.");
            return Ok(new { Message = "Logged out" });
        }
    }
}
```

**Key Security Controls**:
- Uses `SignInManager.PasswordSignInAsync` so passwords are hashed, lockout policies applied, and constant‑time comparisons used.
- Returns generic error messages to prevent user enumeration and reduce information leakage.
- CSRF protection on login/logout via `[ValidateAntiForgeryToken]`, and proper sign‑out via `SignInManager.SignOutAsync` for clean session termination.

In production you want layered controls: hardened Identity options, secure cookies, strict lockout, monitoring, and rate limiting around login endpoints.

**PRODUCTION PATTERN**:

```csharp
using System;
using System.Net;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Authentication.Cookies;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Builder;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Identity;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;

namespace MyApp
{
    public class Startup
    {
        private readonly IConfiguration _config;

        public Startup(IConfiguration config)
        {
            _config = config;
        }

        public void ConfigureServices(IServiceCollection services)
        {
            services.AddDbContext<ApplicationDbContext>();

            services.AddIdentity<IdentityUser, IdentityRole>(options =>
            {
                // Password policy
                options.Password.RequireDigit = true;
                options.Password.RequiredLength = 12;
                options.Password.RequireNonAlphanumeric = true;
                options.Password.RequireUppercase = true;
                options.Password.RequireLowercase = true;

                // Lockout policy
                options.Lockout.MaxFailedAccessAttempts = 5;
                options.Lockout.DefaultLockoutTimeSpan = TimeSpan.FromMinutes(15);
                options.Lockout.AllowedForNewUsers = true;

                // User settings
                options.User.RequireUniqueEmail = true;

                // Sign-in settings
                options.SignIn.RequireConfirmedEmail = true;
            })
            .AddEntityFrameworkStores<ApplicationDbContext>()
            .AddDefaultTokenProviders();

            services.ConfigureApplicationCookie(options =>
            {
                options.Cookie.HttpOnly = true;
                options.Cookie.SecurePolicy = CookieSecurePolicy.Always;
                options.Cookie.SameSite = SameSiteMode.Strict;
                options.Cookie.Name = ".MyApp.Auth";

                options.SlidingExpiration = true;
                options.ExpireTimeSpan = TimeSpan.FromMinutes(20);

                options.Events = new CookieAuthenticationEvents
                {
                    OnValidatePrincipal = SecurityStampValidator.ValidatePrincipalAsync,
                    OnSigningIn = context =>
                    {
                        var logger = context.HttpContext.RequestServices
                            .GetRequiredService<ILogger<Startup>>();
                        logger.LogInformation("User {Name} signing in.",
                            context.Principal?.Identity?.Name);
                        return Task.CompletedTask;
                    },
                    OnValidatePrincipal = context =>
                    {
                        // Hook for additional checks (IP / device fingerprint, etc.)
                        return SecurityStampValidator.ValidatePrincipalAsync(context);
                    }
                };
            });

            services.AddControllersWithViews();

            // Simple IP-based rate limiting for login
            services.AddSingleton<LoginRateLimiter>();
        }

        public void Configure(IApplicationBuilder app)
        {
            if (_config["ASPNETCORE_ENVIRONMENT"] == "Production")
            {
                app.UseHsts();
            }

            app.UseHttpsRedirection();

            app.Use(async (context, next) =>
            {
                // Security headers
                context.Response.Headers["X-Content-Type-Options"] = "nosniff";
                context.Response.Headers["X-Frame-Options"] = "DENY";
                context.Response.Headers["X-XSS-Protection"] = "0";
                context.Response.Headers["Content-Security-Policy"] = "default-src 'self'";
                await next();
            });

            app.UseRouting();
            app.UseAuthentication();
            app.UseAuthorization();

            app.UseEndpoints(endpoints =>
            {
                endpoints.MapControllers();
            });
        }
    }

    [Route("account")]
    [AllowAnonymous]
    public class AccountController : Controller
    {
        private readonly SignInManager<IdentityUser> _signInManager;
        private readonly UserManager<IdentityUser> _userManager;
        private readonly LoginRateLimiter _rateLimiter;
        private readonly ILogger<AccountController> _logger;

        public AccountController(
            SignInManager<IdentityUser> signInManager,
            UserManager<IdentityUser> userManager,
            LoginRateLimiter rateLimiter,
            ILogger<AccountController> logger)
        {
            _signInManager = signInManager;
            _userManager = userManager;
            _rateLimiter = rateLimiter;
            _logger = logger;
        }

        [HttpPost("login")]
        [ValidateAntiForgeryToken]
        public async Task<IActionResult> Login(string email, string password, bool rememberMe)
        {
            var remoteIp = HttpContext.Connection.RemoteIpAddress?.ToString() ?? "unknown";

            if (!_rateLimiter.AllowAttempt(remoteIp))
            {
                _logger.LogWarning("Rate limit exceeded for IP {IP}.", remoteIp);
                return StatusCode((int)HttpStatusCode.TooManyRequests,
                    new { Message = "Too many login attempts. Please wait." });
            }

            if (!ModelState.IsValid || string.IsNullOrWhiteSpace(email) || string.IsNullOrWhiteSpace(password))
            {
                _logger.LogWarning("Invalid login model from IP {IP}.", remoteIp);
                return BadRequest(new { Message = "Invalid login attempt." });
            }

            var user = await _userManager.FindByEmailAsync(email);
            if (user == null)
            {
                // Fake delay to reduce user enumeration via timing
                await Task.Delay(TimeSpan.FromMilliseconds(200));
            }

            var result = await _signInManager.PasswordSignInAsync(
                email,
                password,
                rememberMe,
                lockoutOnFailure: true);

            if (result.Succeeded)
            {
                _logger.LogInformation("Successful login for {Email} from {IP}.", email, remoteIp);
                return Ok(new { Message = "Logged in" });
            }

            if (result.IsLockedOut)
            {
                _logger.LogWarning("Account locked out for {Email} from {IP}.", email, remoteIp);
                return BadRequest(new { Message = "Account locked. Try again later." });
            }

            _logger.LogWarning("Failed login for {Email} from {IP}.", email, remoteIp);
            return BadRequest(new { Message = "Invalid login attempt." });
        }
    }

    // Very simple in-memory rate limiter (replace with robust implementation in real systems)
    public class LoginRateLimiter
    {
        private readonly object _lock = new object();
        private readonly System.Collections.Generic.Dictionary<string, (int Count, DateTime WindowStart)> _attempts
            = new System.Collections.Generic.Dictionary<string, (int, DateTime)>();

        private const int MaxAttempts = 10;
        private static readonly TimeSpan Window = TimeSpan.FromMinutes(5);

        public bool AllowAttempt(string ip)
        {
            lock (_lock)
            {
                if (!_attempts.TryGetValue(ip, out var entry))
                {
                    _attempts[ip] = (1, DateTime.UtcNow);
                    return true;
                }

                if (DateTime.UtcNow - entry.WindowStart > Window)
                {
                    _attempts[ip] = (1, DateTime.UtcNow);
                    return true;
                }

                if (entry.Count >= MaxAttempts)
                {
                    return false;
                }

                _attempts[ip] = (entry.Count + 1, entry.WindowStart);
                return true;
            }
        }
    }
}
```

**Defense in Depth Layers**:
1. **Hardened Identity configuration**
   - Strong password + lockout + confirmed email:
   ```csharp
   options.Lockout.MaxFailedAccessAttempts = 5;
   options.Password.RequiredLength = 12;
   options.SignIn.RequireConfirmedEmail = true;
   ```
   This slows brute force and requires account verification.

2. **Secure session cookies**
   - Mitigates theft and replay of auth cookies:
   ```csharp
   options.Cookie.HttpOnly = true;
   options.Cookie.SecurePolicy = CookieSecurePolicy.Always;
   options.Cookie.SameSite = SameSiteMode.Strict;
   options.ExpireTimeSpan = TimeSpan.FromMinutes(20);
   ```

3. **Rate limiting and monitoring on login**
   - Throttles credential stuffing and creates audit trail:
   ```csharp
   if (!_rateLimiter.AllowAttempt(remoteIp))
   {
       _logger.LogWarning("Rate limit exceeded for IP {IP}.", remoteIp);
       return StatusCode(429);
   }
   ```

**Additional Protections**:
- Enable HTTPS and HSTS in production so cookies are only sent over TLS and downgrade attacks are mitigated.
- Centralized structured logging and alerting on anomalies (e.g., many failures from one IP, logins from unusual geolocations).
- Add MFA (TOTP, WebAuthn) using ASP.NET Core Identity's token providers and enforce it for privileged roles, further reducing the impact of stolen credentials or session cookies.
